#[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalRelationDigest(pub [u64; 5]);

/// Tip5 digest of the backend-projected terminal relation.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
