pub struct TerminalNpoPolynomialColumnLayout {
    pub rows: usize,
    pub log_rows: usize,
    pub column_count: usize,
    pub metadata_columns: usize,
    pub row_kind_selector_columns: usize,
    pub mode_columns: usize,
    pub input_value_columns: usize,
    pub input_present_columns: usize,
    pub output_value_columns: usize,
    pub output_present_columns: usize,
    pub hidden_tip5_value_columns: usize,
    pub hidden_tip5_present_columns: usize,
    pub mmcs_columns: usize,
    pub residual_value_columns: usize,
    pub residual_present_columns: usize,
}

/// Column subset committed by a terminal NPO polynomial FRI checkpoint.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub enum TerminalNpoPolynomialFriColumnSet {
    /// Commit every fixed NPO table column, including deterministic metadata
    /// and residual columns.
    #[default]
    FullTable,
    /// Commit only witness-bearing value columns. Deterministic metadata,
    /// present bits, and residual columns are verifier-derived or relation
    /// outputs in the final backend and should not be paid for in the
    /// low-degree commitment.
    WitnessValues,
    /// One extension-valued quotient column, flattened into terminal
    /// Goldilocks basis columns, for the batched value-padding relation.
    PaddingQuotient,
}

/// FRI commitment shape for the basis-expanded supported-NPO polynomial table.
///
/// The terminal NPO table lives over the verifier-circuit field `F`. The
/// terminal FRI PCS commits Goldilocks codewords, so every `F` column is
/// expanded into its Goldilocks basis coefficients before padding to the
/// verifier-key-derived two-adic row domain.
#[derive(Clone, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalNpoPolynomialFriProfile {
    pub column_set: TerminalNpoPolynomialFriColumnSet,
    pub rows: usize,
    pub padded_rows: usize,
    pub log_rows: usize,
    pub field_basis_dimension: usize,
    pub field_columns: usize,
    pub basis_columns: usize,
    pub proximity: TerminalProximityProfile,
}

/// FRI opening proof for the basis-expanded supported-NPO polynomial columns.
///
/// This is a terminal backend checkpoint, not yet the complete production NPO
/// argument: it proves that the committed basis-expanded column matrix is low
/// degree and opened at a transcript-derived point. The remaining production
/// work is to connect row-polynomial constraints and residual zero checks to
/// this opening.
#[derive(Clone, Serialize, Deserialize)]
pub struct TerminalNpoPolynomialFriOpeningProof {
    pub profile: TerminalNpoPolynomialFriProfile,
    pub commitment: TerminalFriCommitment,
    pub opened_values_basis: Vec<Vec<u64>>,
    pub proof: TerminalCompressedFriProof,
}

/// Transcript-derived opening of terminal NPO polynomial FRI columns.
///
/// `values[column][basis]` is the terminal FRI challenge-field value for one
/// Goldilocks basis column at the derived opening point. This is intentionally
/// not serialized; the verifier derives it from a verified
/// [`TerminalNpoPolynomialFriOpeningProof`] so row-polynomial checks can consume
/// labeled openings without trusting prover-selected labels or points.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct TerminalNpoPolynomialFriOpenedColumns {
    pub profile: TerminalNpoPolynomialFriProfile,
    pub zeta: TerminalFriChallenge,
    pub labels: Vec<String>,
    pub values: Vec<Vec<TerminalFriChallenge>>,
}

/// Combined value-column and padding-quotient opening proof.
///
/// This is the first quotient-backed NPO row-polynomial checkpoint. It proves
/// the witness-value columns are low degree, proves a low-degree quotient for
/// the batched value-column constraints, and opens both at one
/// transcript-derived point with one terminal FRI proof.
#[derive(Clone, Serialize, Deserialize)]
pub struct TerminalNpoPolynomialPaddingQuotientProof {
    pub value_profile: TerminalNpoPolynomialFriProfile,
    pub quotient_profile: TerminalNpoPolynomialFriProfile,
    pub value_commitment: TerminalFriCommitment,
    pub quotient_commitment: TerminalFriCommitment,
    pub opened_value_basis: Vec<Vec<u64>>,
    pub opened_quotient_basis: Vec<Vec<u64>>,
    pub proof: TerminalCompressedFriProof,
}

