    fn terminal_npo_tip5_lookup_air_algebra_quotient_profile(
        trace_profile: &TerminalNpoTip5LookupFriProfile,
    ) -> Result<TerminalNpoTip5LookupAirAlgebraQuotientProfile, NativeTerminalVerifyError> {
        if trace_profile.column_set != TerminalNpoTip5LookupFriColumnSet::FullMain {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_quotient_column_set".into(),
                    expected: TerminalNpoTip5LookupFriColumnSet::FullMain as usize,
                    got: trace_profile.column_set as usize,
                },
            );
        }
        if trace_profile.padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let degree = trace_profile.trace.max_constraint_degree.max(1);
        let padded_rows = trace_profile.padded_rows.checked_mul(degree).ok_or(
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal Tip5 lookup AIR quotient domain overflow".into(),
            },
        )?;
        Ok(TerminalNpoTip5LookupAirAlgebraQuotientProfile {
            trace: trace_profile.trace.clone(),
            rows: trace_profile.rows,
            padded_rows,
            log_rows: padded_rows.trailing_zeros() as usize,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: trace_profile.proximity,
        })
    }

    fn terminal_npo_tip5_lookup_air_algebra_quotient_matrix_goldilocks(
        trace_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        trace_profile: &TerminalNpoTip5LookupFriProfile,
        trace_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
        beta: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if trace_profile.column_set != TerminalNpoTip5LookupFriColumnSet::FullMain {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_column_set".into(),
                    expected: TerminalNpoTip5LookupFriColumnSet::FullMain as usize,
                    got: trace_profile.column_set as usize,
                },
            );
        }
        if trace_matrix.width() != trace_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_width".into(),
                    expected: trace_profile.basis_columns,
                    got: trace_matrix.width(),
                },
            );
        }
        if trace_matrix.height() != trace_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_rows".into(),
                    expected: trace_profile.padded_rows,
                    got: trace_matrix.height(),
                },
            );
        }
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut quotient_values = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            let opened_trace = trace_matrix.interpolate_coset(trace_domain.shift(), point);
            let relation = Self::terminal_npo_tip5_lookup_air_algebra_folded_relation(
                &opened_trace,
                alpha,
            )?;
            let terminal_io =
                Self::terminal_npo_tip5_lookup_air_terminal_io_folded_relation(
                    &opened_trace,
                    trace_profile,
                    alpha,
                )?;
            let window_vanishing =
                Self::terminal_npo_tip5_lookup_permutation_window_vanishing_at_point(
                    trace_domain,
                    trace_profile,
                    point,
                )?;
            let relation = relation + beta * window_vanishing * terminal_io;
            let quotient = relation / trace_domain.vanishing_poly_at_point(point);
            quotient_values.push(quotient);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal Tip5 lookup AIR algebra quotient domain has no successor"
                        .into(),
                }
            })?;
        }
        let quotient = RowMajorMatrix::new_col(quotient_values).flatten_to_base();
        if quotient.width() != quotient_basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: quotient_basis_dimension,
                    got: quotient.width(),
                },
            );
        }
        Ok(quotient)
    }

    fn terminal_npo_tip5_lookup_air_algebra_folded_relation(
        trace: &[TerminalFriChallenge],
        alpha: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        const STATE_SIZE: usize = 16;
        const NS: usize = 4;
        const NBYTES: usize = 8;
        const SPLIT_BC: usize = NS * 2 * NBYTES;
        const PWR: usize = STATE_SIZE - NS;
        const C_KIND: usize = 0;
        const C_IN: usize = 2;
        const RB0: usize = C_IN + STATE_SIZE;
        const ROUND_GROUP: usize = SPLIT_BC + NS + PWR + PWR + STATE_SIZE;
        const ROUND_OUTPUT_OFFSET: usize = SPLIT_BC + NS + 2 * PWR;

        #[inline]
        const fn rb(round: usize) -> usize {
            RB0 + round * ROUND_GROUP
        }
        #[inline]
        const fn b_col(round: usize, lane: usize, byte: usize) -> usize {
            rb(round) + lane * (2 * NBYTES) + byte
        }
        #[inline]
        const fn c_col(round: usize, lane: usize, byte: usize) -> usize {
            rb(round) + lane * (2 * NBYTES) + NBYTES + byte
        }
        #[inline]
        const fn inv_col(round: usize, lane: usize) -> usize {
            rb(round) + SPLIT_BC + lane
        }
        #[inline]
        const fn x2_col(round: usize, lane: usize) -> usize {
            rb(round) + SPLIT_BC + NS + (lane - NS)
        }
        #[inline]
        const fn x3_col(round: usize, lane: usize) -> usize {
            rb(round) + SPLIT_BC + NS + PWR + (lane - NS)
        }
        #[inline]
        const fn rout_col(round: usize, lane: usize) -> usize {
            rb(round) + ROUND_OUTPUT_OFFSET + lane
        }
        #[inline]
        const fn sbox_in_col(round: usize, lane: usize) -> usize {
            if round == 0 {
                C_IN + lane
            } else {
                rout_col(round - 1, lane)
            }
        }

        let required_width = RB0 + TIP5_PERM_ROUNDS * ROUND_GROUP;
        if trace.len() != required_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_opened_trace_width".into(),
                    expected: required_width,
                    got: trace.len(),
                },
            );
        }
        let fe = |value: u64| TerminalFriChallenge::from(Goldilocks::from_u64(value));
        let pow8 = |byte: usize| fe(1u64 << (8 * byte));
        let two32_minus_one = fe((1u64 << 32) - 1);
        let mds = tip5_mds_matrix();

        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        let mut absorb = |constraint: TerminalFriChallenge| {
            folded += coeff * constraint;
            coeff *= alpha;
        };

        let kind = trace[C_KIND];
        absorb(kind * (kind - TerminalFriChallenge::ONE));

        for round in 0..TIP5_PERM_ROUNDS {
            let mut sbox_outputs = Vec::with_capacity(STATE_SIZE);
            for lane in 0..NS {
                let mut recompose_b = TerminalFriChallenge::ZERO;
                let mut recompose_c = TerminalFriChallenge::ZERO;
                let mut low = TerminalFriChallenge::ZERO;
                let mut high = TerminalFriChallenge::ZERO;
                for byte in 0..NBYTES {
                    let b = trace[b_col(round, lane, byte)];
                    let c = trace[c_col(round, lane, byte)];
                    recompose_b += b * pow8(byte);
                    recompose_c += c * pow8(byte);
                    if byte < 4 {
                        low += b * pow8(byte);
                    } else {
                        high += b * pow8(byte - 4);
                    }
                }
                absorb(kind * (recompose_b - trace[sbox_in_col(round, lane)]));
                sbox_outputs.push(recompose_c);

                let g = high - two32_minus_one;
                let inv = trace[inv_col(round, lane)];
                let prod = g * inv;
                absorb(kind * g * (prod - TerminalFriChallenge::ONE));
                absorb(kind * (TerminalFriChallenge::ONE - prod) * low);
            }

            for lane in NS..STATE_SIZE {
                let x = trace[sbox_in_col(round, lane)];
                let x2 = trace[x2_col(round, lane)];
                let x3 = trace[x3_col(round, lane)];
                absorb(kind * (x2 - x * x));
                absorb(kind * (x3 - x2 * x));
                sbox_outputs.push(x3 * x3 * x);
            }

            for lane in 0..STATE_SIZE {
                let mut acc = TerminalFriChallenge::ZERO;
                for column in 0..STATE_SIZE {
                    acc += fe(mds[lane][column]) * sbox_outputs[column];
                }
                let rc = fe(tip5_rc_precomp(
                    TIP5_ROUND_CONSTANTS[round * STATE_SIZE + lane],
                ));
                absorb(kind * (trace[rout_col(round, lane)] - acc - rc));
            }
        }

        Ok(folded)
    }

    fn terminal_npo_tip5_lookup_air_terminal_io_folded_relation(
        trace: &[TerminalFriChallenge],
        profile: &TerminalNpoTip5LookupFriProfile,
        alpha: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let terminal_io_indices = Self::terminal_npo_tip5_lookup_fri_column_indices(
            profile.trace.main_width,
            TerminalNpoTip5LookupFriColumnSet::TerminalIo,
        )?;
        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        for index in terminal_io_indices {
            let value = trace.get(index).copied().ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_terminal_io_opened_trace_width".into(),
                    expected: profile.trace.main_width,
                    got: trace.len(),
                },
            )?;
            folded += coeff * value;
            coeff *= alpha;
        }
        Ok(folded)
    }

    fn terminal_npo_tip5_lookup_npo_rows_io_profile(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        layout: &TerminalNpoPolynomialColumnLayout,
    ) -> Result<TerminalNpoTip5LookupNpoRowsIoProfile, NativeTerminalVerifyError> {
        if layout.rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        if trace_profile.tip5_rows > layout.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_tip5_rows".into(),
                    expected: layout.rows,
                    got: trace_profile.tip5_rows,
                },
            );
        }
        Ok(TerminalNpoTip5LookupNpoRowsIoProfile {
            trace: trace_profile.clone(),
            rows: layout.rows,
            padded_rows: 1usize << layout.log_rows,
            log_rows: layout.log_rows,
            field_basis_dimension: <Goldilocks as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 26,
            basis_columns: 26,
            proximity: TerminalProximityProfile::production_60bit(),
        })
    }

    fn terminal_npo_tip5_lookup_npo_rows_value_bridge_quotient_profile(
        lookup_io_profile: &TerminalNpoTip5LookupNpoRowsIoProfile,
    ) -> Result<TerminalNpoTip5LookupNpoRowsValueBridgeQuotientProfile, NativeTerminalVerifyError>
    {
        if lookup_io_profile.padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let padded_rows = lookup_io_profile.padded_rows * 2;
        Ok(TerminalNpoTip5LookupNpoRowsValueBridgeQuotientProfile {
            rows: lookup_io_profile.rows,
            padded_rows,
            log_rows: lookup_io_profile.log_rows + 1,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: lookup_io_profile.proximity,
        })
    }

    fn terminal_npo_tip5_lookup_npo_rows_io_matrix_goldilocks<F>(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        columns: &TerminalNpoPolynomialColumns<F>,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<
        (
            TerminalNpoTip5LookupNpoRowsIoProfile,
            RowMajorMatrix<Goldilocks>,
        ),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        if trace.width() != trace_profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_trace_width".into(),
                    expected: trace_profile.main_width,
                    got: trace.width(),
                },
            );
        }
        if trace.height() != trace_profile.main_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_trace_rows".into(),
                    expected: trace_profile.main_rows,
                    got: trace.height(),
                },
            );
        }
        let profile =
            Self::terminal_npo_tip5_lookup_npo_rows_io_profile(trace_profile, &columns.layout)?;
        let mut values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        let is_tip5_index = Self::terminal_npo_polynomial_column_index(columns, "is_tip5")?;
        let mut tip5_row = 0usize;
        for row in 0..columns.layout.rows {
            let is_tip5 = Self::terminal_npo_polynomial_column_base_value(
                columns,
                is_tip5_index,
                row,
                "is_tip5",
            )?;
            if is_tip5 == Goldilocks::ZERO {
                continue;
            }
            let trace_row = profile.trace.permutation_row_offset + tip5_row;
            if trace_row >= profile.trace.main_rows {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "tip5_lookup_npo_rows_io_trace_row".into(),
                        expected: profile.trace.main_rows,
                        got: trace_row,
                    },
                );
            }
            for limb in 0..16 {
                values[row * profile.basis_columns + limb] =
                    trace.values[trace_row * trace.width() + 2 + limb];
            }
            for limb in 0..10 {
                values[row * profile.basis_columns + 16 + limb] =
                    trace.values[trace_row * trace.width() + 542 + limb];
            }
            tip5_row += 1;
        }
        if tip5_row != profile.trace.tip5_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_tip5_rows".into(),
                    expected: profile.trace.tip5_rows,
                    got: tip5_row,
                },
            );
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_tip5_lookup_io_projection_matrix_from_columns_goldilocks<F>(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<
        (TerminalNpoTip5LookupFriProfile, RowMajorMatrix<Goldilocks>),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let profile = Self::terminal_npo_tip5_lookup_fri_profile_for_column_set(
            trace_profile,
            TerminalNpoTip5LookupFriColumnSet::TerminalIo,
        )?;
        let mut values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        let is_tip5_index = Self::terminal_npo_polynomial_column_index(columns, "is_tip5")?;
        let mut tip5_row = 0usize;
        for row in 0..columns.layout.rows {
            let is_tip5 = Self::terminal_npo_polynomial_column_base_value(
                columns,
                is_tip5_index,
                row,
                "is_tip5",
            )?;
            if is_tip5 == Goldilocks::ZERO {
                continue;
            }
            let target_row = profile.trace.permutation_row_offset + tip5_row;
            if target_row >= profile.padded_rows {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "tip5_lookup_io_projection_rows".into(),
                        expected: profile.padded_rows,
                        got: target_row,
                    },
                );
            }
            for limb in 0..16 {
                let value = Self::terminal_npo_polynomial_tip5_input_lane_base_value(
                    columns, row, limb,
                )?;
                values[target_row * profile.basis_columns + limb] = value;
            }
            for limb in 0..10 {
                let label = format!("output_value_{limb}");
                let value_index = Self::terminal_npo_polynomial_column_index(columns, &label)?;
                let value = Self::terminal_npo_polynomial_column_base_value(
                    columns,
                    value_index,
                    row,
                    &label,
                )?;
                values[target_row * profile.basis_columns + 16 + limb] = value;
            }
            tip5_row += 1;
        }
        if tip5_row != profile.trace.tip5_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_io_projection_tip5_rows".into(),
                    expected: profile.trace.tip5_rows,
                    got: tip5_row,
                },
            );
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_tip5_lookup_io_bridge_quotient_matrix_goldilocks(
        io_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        io_profile: &TerminalNpoTip5LookupFriProfile,
        lookup_io_matrix: &RowMajorMatrix<Goldilocks>,
        npo_io_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_lookup_io_matrix_shape(
            "tip5_lookup_io_bridge_lookup",
            io_profile,
            lookup_io_matrix,
        )?;
        Self::validate_terminal_npo_tip5_lookup_io_matrix_shape(
            "tip5_lookup_io_bridge_npo",
            io_profile,
            npo_io_matrix,
        )?;
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut combined_basis_evals =
            vec![Vec::with_capacity(io_profile.padded_rows); quotient_basis_dimension];
        for row in 0..io_profile.padded_rows {
            let mut folded = TerminalFriChallenge::ZERO;
            let mut coeff = TerminalFriChallenge::ONE;
            for column in 0..io_profile.basis_columns {
                let lookup_value = TerminalFriChallenge::from(
                    lookup_io_matrix.values[row * io_profile.basis_columns + column],
                );
                let npo_value = TerminalFriChallenge::from(
                    npo_io_matrix.values[row * io_profile.basis_columns + column],
                );
                folded += coeff * (lookup_value - npo_value);
                coeff *= alpha;
            }
            let basis = folded.as_basis_coefficients_slice();
            for basis_index in 0..quotient_basis_dimension {
                combined_basis_evals[basis_index].push(
                    basis
                        .get(basis_index)
                        .copied()
                        .unwrap_or(Goldilocks::ZERO),
                );
            }
        }

        let mut quotient_values = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            let folded_basis = combined_basis_evals
                .iter()
                .map(|basis_evals| io_domain.evaluate_polynomial_at(basis_evals, point))
                .collect::<Vec<_>>();
            let folded =
                <TerminalFriChallenge as ExtensionField<Goldilocks>>::from_ext_basis_coefficients(
                    &folded_basis,
                )
                .ok_or(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: quotient_basis_dimension,
                        got: folded_basis.len(),
                    },
                )?;
            let z_h = io_domain.vanishing_poly_at_point(point);
            quotient_values.push(folded / z_h);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal Tip5 lookup IO bridge quotient domain has no successor"
                        .into(),
                }
            })?;
        }
        Ok(RowMajorMatrix::new_col(quotient_values).flatten_to_base())
    }

    fn terminal_npo_tip5_lookup_io_support_bridge_quotient_matrix_goldilocks(
        io_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        io_profile: &TerminalNpoTip5LookupFriProfile,
        lookup_io_matrix: &RowMajorMatrix<Goldilocks>,
        npo_io_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
        beta: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_lookup_io_matrix_shape(
            "tip5_lookup_io_support_bridge_lookup",
            io_profile,
            lookup_io_matrix,
        )?;
        Self::validate_terminal_npo_tip5_lookup_io_matrix_shape(
            "tip5_lookup_io_support_bridge_npo",
            io_profile,
            npo_io_matrix,
        )?;
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut lookup_basis_evals =
            vec![Vec::with_capacity(io_profile.padded_rows); quotient_basis_dimension];
        let mut diff_basis_evals =
            vec![Vec::with_capacity(io_profile.padded_rows); quotient_basis_dimension];
        for row in 0..io_profile.padded_rows {
            let mut folded_lookup = TerminalFriChallenge::ZERO;
            let mut folded_diff = TerminalFriChallenge::ZERO;
            let mut coeff = TerminalFriChallenge::ONE;
            for column in 0..io_profile.basis_columns {
                let lookup_value = TerminalFriChallenge::from(
                    lookup_io_matrix.values[row * io_profile.basis_columns + column],
                );
                let npo_value = TerminalFriChallenge::from(
                    npo_io_matrix.values[row * io_profile.basis_columns + column],
                );
                folded_lookup += coeff * lookup_value;
                folded_diff += coeff * (lookup_value - npo_value);
                coeff *= alpha;
            }
            let lookup_basis = folded_lookup.as_basis_coefficients_slice();
            let diff_basis = folded_diff.as_basis_coefficients_slice();
            for basis_index in 0..quotient_basis_dimension {
                lookup_basis_evals[basis_index].push(
                    lookup_basis
                        .get(basis_index)
                        .copied()
                        .unwrap_or(Goldilocks::ZERO),
                );
                diff_basis_evals[basis_index].push(
                    diff_basis
                        .get(basis_index)
                        .copied()
                        .unwrap_or(Goldilocks::ZERO),
                );
            }
        }

        let mut quotient_values = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            let lookup_basis = lookup_basis_evals
                .iter()
                .map(|basis_evals| io_domain.evaluate_polynomial_at(basis_evals, point))
                .collect::<Vec<_>>();
            let diff_basis = diff_basis_evals
                .iter()
                .map(|basis_evals| io_domain.evaluate_polynomial_at(basis_evals, point))
                .collect::<Vec<_>>();
            let folded_lookup =
                <TerminalFriChallenge as ExtensionField<Goldilocks>>::from_ext_basis_coefficients(
                    &lookup_basis,
                )
                .ok_or(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: quotient_basis_dimension,
                        got: lookup_basis.len(),
                    },
                )?;
            let folded_diff =
                <TerminalFriChallenge as ExtensionField<Goldilocks>>::from_ext_basis_coefficients(
                    &diff_basis,
                )
                .ok_or(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: quotient_basis_dimension,
                        got: diff_basis.len(),
                    },
                )?;
            let window_vanishing =
                Self::terminal_npo_tip5_lookup_permutation_window_vanishing_at_point(
                    io_domain, io_profile, point,
                )?;
            let relation = folded_diff + beta * window_vanishing * folded_lookup;
            let z_h = io_domain.vanishing_poly_at_point(point);
            quotient_values.push(relation / z_h);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason:
                        "terminal Tip5 lookup IO support bridge quotient domain has no successor"
                            .into(),
                }
            })?;
        }
        Ok(RowMajorMatrix::new_col(quotient_values).flatten_to_base())
    }

    fn terminal_npo_tip5_lookup_npo_rows_value_bridge_quotient_matrix_goldilocks<F>(
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        lookup_io_profile: &TerminalNpoTip5LookupNpoRowsIoProfile,
        value_profile: &TerminalNpoPolynomialFriProfile,
        lookup_io_matrix: &RowMajorMatrix<Goldilocks>,
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        alpha: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        if lookup_io_matrix.width() != lookup_io_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_value_bridge_lookup_width".into(),
                    expected: lookup_io_profile.basis_columns,
                    got: lookup_io_matrix.width(),
                },
            );
        }
        if lookup_io_matrix.height() != lookup_io_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_value_bridge_lookup_rows".into(),
                    expected: lookup_io_profile.padded_rows,
                    got: lookup_io_matrix.height(),
                },
            );
        }
        if lookup_io_profile.padded_rows != value_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_value_bridge_domain_rows".into(),
                    expected: value_profile.padded_rows,
                    got: lookup_io_profile.padded_rows,
                },
            );
        }

        let mut lookup_evals = Vec::with_capacity(lookup_io_profile.basis_columns);
        for column in 0..lookup_io_profile.basis_columns {
            let mut evals = Vec::with_capacity(lookup_io_profile.padded_rows);
            for row in 0..lookup_io_profile.padded_rows {
                evals.push(lookup_io_matrix.values[row * lookup_io_profile.basis_columns + column]);
            }
            lookup_evals.push(evals);
        }
        let value_indices = Self::terminal_npo_polynomial_fri_column_indices(
            columns,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
        )?;
        let value_labels = value_indices
            .iter()
            .map(|index| columns.labels[*index].clone())
            .collect::<Vec<_>>();
        let value_basis_evals = value_indices
            .iter()
            .map(|index| {
                Self::terminal_npo_polynomial_column_basis_evals(
                    columns,
                    value_profile,
                    *index,
                    0,
                )
            })
            .collect::<Vec<_>>();
        let mut selector_cache = HashMap::<String, Vec<Goldilocks>>::new();
        let selector = |cache: &mut HashMap<String, Vec<Goldilocks>>,
                        label: &str,
                        present_label: &str|
         -> Result<Vec<Goldilocks>, NativeTerminalVerifyError> {
            let key = format!("{label}:{present_label}");
            if let Some(evals) = cache.get(&key) {
                return Ok(evals.clone());
            }
            if !verifier_columns
                .labels
                .iter()
                .any(|candidate| candidate == present_label)
            {
                let evals = vec![Goldilocks::ZERO; value_profile.padded_rows];
                cache.insert(key, evals.clone());
                return Ok(evals);
            }
            let evals = Self::terminal_npo_polynomial_product_selector_evals(
                verifier_columns,
                value_profile,
                &["is_tip5", present_label],
            )?;
            cache.insert(key, evals.clone());
            Ok(evals)
        };

        let mut quotient_values = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            let relation = Self::terminal_npo_tip5_lookup_npo_rows_value_bridge_relation_at_point(
                value_domain,
                point,
                alpha,
                &lookup_evals,
                &value_labels,
                &value_basis_evals,
                &mut selector_cache,
                selector,
            )?;
            let z_h = value_domain.vanishing_poly_at_point(point);
            quotient_values.push(relation / z_h);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason:
                        "terminal Tip5 lookup NPO-row value bridge quotient domain has no successor"
                            .into(),
                }
            })?;
        }
        Ok(RowMajorMatrix::new_col(quotient_values).flatten_to_base())
    }

    fn terminal_npo_tip5_lookup_npo_rows_value_bridge_relation_at_point(
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        point: TerminalFriChallenge,
        alpha: TerminalFriChallenge,
        lookup_evals: &[Vec<Goldilocks>],
        value_labels: &[String],
        value_basis_evals: &[Vec<Goldilocks>],
        selector_cache: &mut HashMap<String, Vec<Goldilocks>>,
        mut selector: impl FnMut(
            &mut HashMap<String, Vec<Goldilocks>>,
            &str,
            &str,
        ) -> Result<Vec<Goldilocks>, NativeTerminalVerifyError>,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let value_at = |label: &str| -> TerminalFriChallenge {
            value_labels
                .iter()
                .position(|candidate| candidate == label)
                .map(|index| value_domain.evaluate_polynomial_at(&value_basis_evals[index], point))
                .unwrap_or(TerminalFriChallenge::ZERO)
        };
        let mut relation = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        for limb in 0..16 {
            let lookup = value_domain.evaluate_polynomial_at(&lookup_evals[limb], point);
            let input_label = format!("input_value_{limb}");
            let input_present = format!("input_present_{limb}");
            let input_selector = selector(selector_cache, &input_label, &input_present)?;
            let hidden_label = format!("hidden_tip5_value_{limb}");
            let hidden_present = format!("hidden_tip5_present_{limb}");
            let hidden_selector = selector(selector_cache, &hidden_label, &hidden_present)?;
            let expected = value_domain.evaluate_polynomial_at(&input_selector, point)
                * value_at(&input_label)
                + value_domain.evaluate_polynomial_at(&hidden_selector, point)
                    * value_at(&hidden_label);
            relation += coeff * (lookup - expected);
            coeff *= alpha;
        }
        for limb in 0..10 {
            let lookup = value_domain.evaluate_polynomial_at(&lookup_evals[16 + limb], point);
            let output_label = format!("output_value_{limb}");
            let output_present = format!("output_present_{limb}");
            let output_selector = selector(selector_cache, &output_label, &output_present)?;
            let expected =
                value_domain.evaluate_polynomial_at(&output_selector, point) * value_at(&output_label);
            relation += coeff * (lookup - expected);
            coeff *= alpha;
        }
        Ok(relation)
    }

    fn validate_terminal_npo_tip5_lookup_io_matrix_shape(
        label: &str,
        profile: &TerminalNpoTip5LookupFriProfile,
        matrix: &RowMajorMatrix<Goldilocks>,
    ) -> Result<(), NativeTerminalVerifyError> {
        if matrix.width() != profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_width"),
                    expected: profile.basis_columns,
                    got: matrix.width(),
                },
            );
        }
        if matrix.height() != profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_rows"),
                    expected: profile.padded_rows,
                    got: matrix.height(),
                },
            );
        }
        Ok(())
    }

    fn terminal_npo_polynomial_tip5_input_lane_base_value<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        row: usize,
        limb: usize,
    ) -> Result<Goldilocks, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let input_present_label = format!("input_present_{limb}");
        if let Ok(input_present_index) =
            Self::terminal_npo_polynomial_column_index(columns, &input_present_label)
        {
            let input_present = Self::terminal_npo_polynomial_column_base_value(
                columns,
                input_present_index,
                row,
                &input_present_label,
            )?;
            if input_present != Goldilocks::ZERO {
                let input_label = format!("input_value_{limb}");
                let input_index = Self::terminal_npo_polynomial_column_index(columns, &input_label)?;
                return Self::terminal_npo_polynomial_column_base_value(
                    columns,
                    input_index,
                    row,
                    &input_label,
                );
            }
        }
        let hidden_present_label = format!("hidden_tip5_present_{limb}");
        if let Ok(hidden_present_index) =
            Self::terminal_npo_polynomial_column_index(columns, &hidden_present_label)
        {
            let hidden_present = Self::terminal_npo_polynomial_column_base_value(
                columns,
                hidden_present_index,
                row,
                &hidden_present_label,
            )?;
            if hidden_present != Goldilocks::ZERO {
                let hidden_label = format!("hidden_tip5_value_{limb}");
                let hidden_index = Self::terminal_npo_polynomial_column_index(columns, &hidden_label)?;
                return Self::terminal_npo_polynomial_column_base_value(
                    columns,
                    hidden_index,
                    row,
                    &hidden_label,
                );
            }
        }
        Ok(Goldilocks::ZERO)
    }

    fn terminal_npo_polynomial_column_base_value<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        column_index: usize,
        row: usize,
        label: &str,
    ) -> Result<Goldilocks, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let value = columns
            .columns
            .get(column_index)
            .and_then(|column| column.get(row))
            .ok_or_else(
                || NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: label.into(),
                    expected: row + 1,
                    got: columns
                        .columns
                        .get(column_index)
                        .map(Vec::len)
                        .unwrap_or(0),
                },
            )?;
        Self::terminal_npo_table_base_goldilocks(row, label, value)
    }

    fn terminal_npo_tip5_lookup_permutation_window_vanishing_at_point(
        domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        profile: &TerminalNpoTip5LookupFriProfile,
        point: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let start = profile.trace.permutation_row_offset;
        let end = start + profile.trace.tip5_rows;
        if end > profile.trace.main_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_permutation_window".into(),
                    expected: profile.trace.main_rows,
                    got: end,
                },
            );
        }
        let mut acc = TerminalFriChallenge::ONE;
        let mut row_point = TerminalFriChallenge::from(domain.first_point());
        for row in 0..profile.trace.main_rows {
            if row >= start && row < end {
                acc *= point - row_point;
            }
            row_point = domain.next_point(row_point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal Tip5 lookup domain has no successor".into(),
                }
            })?;
        }
        Ok(acc)
    }

    fn terminal_npo_polynomial_fri_profile_for_layout<F>(
        layout: &TerminalNpoPolynomialColumnLayout,
    ) -> Result<TerminalNpoPolynomialFriProfile, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_polynomial_fri_profile_for_column_count::<F>(
            layout,
            TerminalNpoPolynomialFriColumnSet::FullTable,
            layout.column_count,
        )
    }

    fn terminal_npo_polynomial_padding_quotient_profile(
        layout: &TerminalNpoPolynomialColumnLayout,
    ) -> Result<TerminalNpoPolynomialFriProfile, NativeTerminalVerifyError> {
        if layout.rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let padded_rows = 1usize << (layout.log_rows + 1);
        Ok(TerminalNpoPolynomialFriProfile {
            column_set: TerminalNpoPolynomialFriColumnSet::PaddingQuotient,
            rows: layout.rows,
            padded_rows,
            log_rows: layout.log_rows + 1,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: TerminalProximityProfile::production_60bit(),
        })
    }

    fn terminal_npo_polynomial_fri_profile_for_column_count<F>(
        layout: &TerminalNpoPolynomialColumnLayout,
        column_set: TerminalNpoPolynomialFriColumnSet,
        field_columns: usize,
    ) -> Result<TerminalNpoPolynomialFriProfile, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        if layout.rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        if field_columns == 0 {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_fri_columns".into(),
                    expected: 1,
                    got: 0,
                },
            );
        }
        let padded_rows = 1usize << layout.log_rows;
        let field_basis_dimension = <F as BasedVectorSpace<Goldilocks>>::DIMENSION;
        Ok(TerminalNpoPolynomialFriProfile {
            column_set,
            rows: layout.rows,
            padded_rows,
            log_rows: layout.log_rows,
            field_basis_dimension,
            field_columns,
            basis_columns: field_columns * field_basis_dimension,
            proximity: TerminalProximityProfile::production_60bit(),
        })
    }

    pub fn terminal_npo_polynomial_basis_matrix_goldilocks<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<
        (TerminalNpoPolynomialFriProfile, RowMajorMatrix<Goldilocks>),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_polynomial_basis_matrix_for_column_set_goldilocks(
            columns,
            TerminalNpoPolynomialFriColumnSet::FullTable,
        )
    }

    pub fn terminal_npo_polynomial_value_basis_matrix_goldilocks<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<
        (TerminalNpoPolynomialFriProfile, RowMajorMatrix<Goldilocks>),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_polynomial_basis_matrix_for_column_set_goldilocks(
            columns,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
        )
    }

    fn terminal_npo_polynomial_basis_matrix_for_column_set_goldilocks<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        column_set: TerminalNpoPolynomialFriColumnSet,
    ) -> Result<
        (TerminalNpoPolynomialFriProfile, RowMajorMatrix<Goldilocks>),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let column_indices = Self::terminal_npo_polynomial_fri_column_indices(columns, column_set)?;
        let profile = Self::terminal_npo_polynomial_fri_profile_for_column_count::<F>(
            &columns.layout,
            column_set,
            column_indices.len(),
        )?;
        let mut values = Vec::with_capacity(profile.padded_rows * profile.basis_columns);
        for row in 0..profile.padded_rows {
            for column_index in &column_indices {
                let column = &columns.columns[*column_index];
                let basis = if row < profile.rows {
                    column[row].as_basis_coefficients_slice()
                } else {
                    &[]
                };
                for basis_index in 0..profile.field_basis_dimension {
                    values.push(basis.get(basis_index).copied().unwrap_or(Goldilocks::ZERO));
                }
            }
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_polynomial_fri_column_indices<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        column_set: TerminalNpoPolynomialFriColumnSet,
    ) -> Result<Vec<usize>, NativeTerminalVerifyError> {
        let indices = match column_set {
            TerminalNpoPolynomialFriColumnSet::FullTable => {
                (0..columns.columns.len()).collect::<Vec<_>>()
            }
            TerminalNpoPolynomialFriColumnSet::WitnessValues => columns
                .labels
                .iter()
                .enumerate()
                .filter_map(|(index, label)| {
                    Self::terminal_npo_polynomial_label_is_witness_value(label).then_some(index)
                })
                .collect::<Vec<_>>(),
            TerminalNpoPolynomialFriColumnSet::PaddingQuotient => Vec::new(),
        };
        if indices.is_empty() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_fri_column_indices".into(),
                    expected: 1,
                    got: 0,
                },
            );
        }
        Ok(indices)
    }

    pub fn terminal_fri_parameters(
        profile: TerminalProximityProfile,
        mmcs: TerminalFriChallengeMmcs,
    ) -> Result<FriParameters<TerminalFriChallengeMmcs>, NativeTerminalVerifyError> {
        let parameters = profile.proof_parameters();
        Self::validate_terminal_production_parameters(parameters)?;
        Self::validate_terminal_proximity_parameters(&profile, parameters)?;
        Ok(FriParameters {
            log_blowup: profile.log_blowup as usize,
            log_final_poly_len: profile.log_final_poly_len as usize,
            max_log_arity: profile.max_log_arity as usize,
            num_queries: profile.num_queries as usize,
            commit_proof_of_work_bits: 0,
            query_proof_of_work_bits: profile.query_pow_bits as usize,
            mmcs,
        })
    }

    pub fn terminal_fri_pcs_and_challenger(
        profile: TerminalProximityProfile,
    ) -> Result<(TerminalFriPcs, TerminalFriChallenger), NativeTerminalVerifyError> {
        let perm = Tip5Perm;
        let hash = TerminalTip5Sponge::new(perm);
        let compress = TerminalTip5Compress::new(perm);
        let val_mmcs = TerminalFriValMmcs::new(hash, compress, 0);
        let challenge_mmcs = TerminalFriChallengeMmcs::new(val_mmcs.clone());
        let fri_parameters = Self::terminal_fri_parameters(profile, challenge_mmcs)?;
        Ok((
            TerminalFriPcs::new(TerminalFriDft::default(), val_mmcs, fri_parameters),
            TerminalFriChallenger::new(perm),
        ))
    }

    pub fn terminal_compact_composition_fri_profile(
        rows: usize,
        padded_rows: usize,
    ) -> Result<TerminalCompactCompositionFriProfile, NativeTerminalVerifyError> {
        if rows == 0 || padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        if !padded_rows.is_power_of_two() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal compact composition FRI rows must be a power of two".into(),
                },
            );
        }
        if rows > padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_rows".into(),
                    expected: padded_rows,
                    got: rows,
                },
            );
        }
        Ok(TerminalCompactCompositionFriProfile {
            rows,
            padded_rows,
            log_rows: padded_rows.trailing_zeros() as usize,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: TerminalProximityProfile::production_60bit(),
        })
    }

    fn seed_terminal_compact_composition_fri_challenger(
        challenger: &mut TerminalFriChallenger,
        transcript_label: &str,
        prelude: &TerminalProofPrelude,
        profile: &TerminalCompactCompositionFriProfile,
    ) {
        Self::observe_terminal_fri_str(challenger, transcript_label);
        for limb in prelude.challenge_digest.0 {
            challenger.observe(Goldilocks::from_u64(limb));
        }
        for limb in prelude.public_values_digest.0 {
            challenger.observe(Goldilocks::from_u64(limb));
        }
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.security_bits as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.log_blowup as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.num_queries as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.query_pow_bits as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.query_pow_nonce);
        Self::observe_terminal_fri_u64(challenger, profile.rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.padded_rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.log_rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.field_basis_dimension as u64);
        Self::observe_terminal_fri_u64(challenger, profile.field_columns as u64);
        Self::observe_terminal_fri_u64(challenger, profile.basis_columns as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.scheme_id as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.log_blowup as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.num_queries as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.query_pow_bits as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.max_log_arity as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.log_final_poly_len as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.pure_query_bits as u64);
    }

    pub fn prove_terminal_compact_composition_fri_goldilocks(
        prelude: &TerminalProofPrelude,
        transcript_label: &str,
        profile: TerminalCompactCompositionFriProfile,
        matrix: RowMajorMatrix<Goldilocks>,
    ) -> Result<TerminalCompactCompositionFriProof, NativeTerminalVerifyError> {
        if profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: profile.proximity.proof_parameters(),
                },
            );
        }
        if matrix.height() != profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_matrix_rows".into(),
                    expected: profile.padded_rows,
                    got: matrix.height(),
                },
            );
        }
        if matrix.width() != profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_matrix_width".into(),
                    expected: profile.basis_columns,
                    got: matrix.width(),
                },
            );
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(profile.proximity)?;
        Self::seed_terminal_compact_composition_fri_challenger(
            &mut challenger,
            transcript_label,
            prelude,
            &profile,
        );
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                profile.padded_rows,
            );
        let (commitment, data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(domain, matrix)],
            );
        challenger.observe(commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let (opened_values, plain_proof) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::open(
                &pcs,
                vec![(&data, vec![vec![zeta]])],
                &mut challenger,
            );
        let opened_values_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 0)?;
        let opened_values_ext = opened_values[0][0][0].clone();

        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_compact_composition_fri_challenger(
            &mut query_challenger,
            transcript_label,
            prelude,
            &profile,
        );
        query_challenger.observe(commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe_algebra_slice(&opened_values_ext);
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;
        Ok(TerminalCompactCompositionFriProof {
            profile,
            commitment,
            opened_values_basis,
            proof,
        })
    }

    pub fn verify_terminal_compact_composition_fri_goldilocks(
        prelude: &TerminalProofPrelude,
        transcript_label: &str,
        expected_profile: &TerminalCompactCompositionFriProfile,
        proof: &TerminalCompactCompositionFriProof,
    ) -> Result<Vec<TerminalFriChallenge>, NativeTerminalVerifyError> {
        if &proof.profile != expected_profile {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_profile".into(),
                    expected: expected_profile.basis_columns,
                    got: proof.profile.basis_columns,
                },
            );
        }
        if proof.profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.profile.proximity.proof_parameters(),
                },
            );
        }
        if proof.opened_values_basis.len() != proof.profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.profile.basis_columns,
                    got: proof.opened_values_basis.len(),
                },
            );
        }
        let mut opened_values = Vec::with_capacity(proof.opened_values_basis.len());
        for basis in &proof.opened_values_basis {
            opened_values.push(Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(
                basis,
            )?);
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(proof.profile.proximity)?;
        Self::seed_terminal_compact_composition_fri_challenger(
            &mut challenger,
            transcript_label,
            prelude,
            &proof.profile,
        );
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                proof.profile.padded_rows,
            );
        challenger.observe(proof.commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let restored = Self::decompress_terminal_fri_proof(&proof.proof)?;
        <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::verify(
            &pcs,
            vec![(
                proof.commitment.clone(),
                vec![(domain, vec![(zeta, opened_values.clone())])],
            )],
            &restored,
            &mut challenger,
        )
        .map_err(|err| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: format!("terminal compact composition FRI verification failed: {err:?}"),
            }
        })?;
        Ok(opened_values)
    }

    pub fn terminal_npo_exhaustive_residual_compact_composition_profile_goldilocks<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
    ) -> Result<TerminalCompactCompositionFriProfile, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let rows = Self::terminal_npo_polynomial_profile::<F>(verifying_key).residual_components;
        let padded_rows = rows.next_power_of_two();
        Self::terminal_compact_composition_fri_profile(rows, padded_rows)
    }

    pub fn prove_terminal_npo_exhaustive_residual_compact_composition_from_values_goldilocks(
        prelude: &TerminalProofPrelude,
        residual_values: &[Goldilocks],
    ) -> Result<TerminalNpoExhaustiveResidualCompactCompositionProof, NativeTerminalVerifyError>
    {
        let profile = Self::terminal_compact_composition_fri_profile(
            residual_values.len(),
            residual_values.len().next_power_of_two(),
        )?;
        let matrix = Self::terminal_compact_composition_matrix_from_goldilocks_values(
            residual_values,
            &profile,
        )?;
        let composition = Self::prove_terminal_compact_composition_fri_goldilocks(
            prelude,
            Self::terminal_npo_exhaustive_residual_compact_composition_label(),
            profile,
            matrix,
        )?;
        Ok(TerminalNpoExhaustiveResidualCompactCompositionProof { composition })
    }

    pub fn prove_terminal_npo_exhaustive_residual_compact_composition_goldilocks(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<Goldilocks>,
        prelude: &TerminalProofPrelude,
        witness: &TerminalWitness<Goldilocks>,
    ) -> Result<TerminalNpoExhaustiveResidualCompactCompositionProof, NativeTerminalVerifyError>
    {
        let residual_values =
            self.terminal_npo_exhaustive_residual_values_goldilocks(verifying_key, witness)?;
        Self::prove_terminal_npo_exhaustive_residual_compact_composition_from_values_goldilocks(
            prelude,
            &residual_values,
        )
    }

    pub fn verify_terminal_npo_exhaustive_residual_compact_composition_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoExhaustiveResidualCompactCompositionProof,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let expected_profile =
            Self::terminal_npo_exhaustive_residual_compact_composition_profile_goldilocks(
                verifying_key,
            )?;
        let opened = Self::verify_terminal_compact_composition_fri_goldilocks(
            prelude,
            Self::terminal_npo_exhaustive_residual_compact_composition_label(),
            &expected_profile,
            &proof.composition,
        )?;
        if opened
            .iter()
            .any(|value| *value != TerminalFriChallenge::ZERO)
        {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: Self::terminal_npo_exhaustive_residual_compact_composition_label()
                        .into(),
                },
            );
        }
        Ok(())
    }

    pub fn compress_terminal_fri_proof(
        proof: &TerminalFriProof,
        query_indices: &[usize],
    ) -> Result<TerminalCompressedFriProof, NativeTerminalVerifyError> {
        if proof.query_proofs.len() != query_indices.len() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compressed_fri_query_indices".into(),
                    expected: proof.query_proofs.len(),
                    got: query_indices.len(),
                },
            );
        }
        let query_count = proof.query_proofs.len();
        let input_batch_count = proof
            .query_proofs
            .first()
            .map(|query| query.input_proof.len())
            .unwrap_or(0);
        for query in &proof.query_proofs {
            if query.input_proof.len() != input_batch_count {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "terminal_compressed_fri_input_batch_count".into(),
                        expected: input_batch_count,
                        got: query.input_proof.len(),
                    },
                );
            }
        }
        let mut input_batches = Vec::with_capacity(input_batch_count);
        for batch in 0..input_batch_count {
            let mut opened_values = Vec::with_capacity(query_count);
            let mut paths = Vec::with_capacity(query_count);
            for (query_index, query) in query_indices.iter().zip(&proof.query_proofs) {
                let opening = &query.input_proof[batch];
                opened_values.push(opening.opened_values.clone());
                paths.push((
                    *query_index,
                    opening.opening_proof.clone(),
                ));
            }
            input_batches.push(TerminalCompressedFriInputBatch {
                opened_values,
                pruned_opening_proof: Self::terminal_prune_binary_merkle_paths(&paths)?,
            });
        }

        let commit_round_count = proof
            .query_proofs
            .first()
            .map(|query| query.commit_phase_openings.len())
            .unwrap_or(0);
        for query in &proof.query_proofs {
            if query.commit_phase_openings.len() != commit_round_count {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "terminal_compressed_fri_commit_round_count".into(),
                        expected: commit_round_count,
                        got: query.commit_phase_openings.len(),
                    },
                );
            }
        }
        let mut cumulative_log_arity = 0usize;
        let mut commit_rounds = Vec::with_capacity(commit_round_count);
        for round in 0..commit_round_count {
            let log_arity = proof.query_proofs[0].commit_phase_openings[round].log_arity;
            let mut sibling_values = Vec::with_capacity(query_count);
            let mut paths = Vec::with_capacity(query_count);
            cumulative_log_arity += log_arity as usize;
            for (query_index, query) in query_indices.iter().zip(&proof.query_proofs) {
                let opening = &query.commit_phase_openings[round];
                if opening.log_arity != log_arity {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                            reason: "terminal compressed FRI log-arity mismatch".into(),
                        },
                    );
                }
                sibling_values.push(opening.sibling_values.clone());
                paths.push((
                    *query_index >> cumulative_log_arity,
                    opening.opening_proof.clone(),
                ));
            }
            commit_rounds.push(TerminalCompressedFriCommitRound {
                log_arity,
                sibling_values,
                pruned_opening_proof: Self::terminal_prune_binary_merkle_paths(&paths)?,
            });
        }

        Ok(TerminalCompressedFriProof {
            commit_phase_commits: proof.commit_phase_commits.clone(),
            commit_pow_witnesses: proof.commit_pow_witnesses.clone(),
            input_batches,
            commit_rounds,
            final_poly: proof.final_poly.clone(),
            query_pow_witness: proof.query_pow_witness,
        })
    }

    pub fn decompress_terminal_fri_proof(
        compressed: &TerminalCompressedFriProof,
    ) -> Result<TerminalFriProof, NativeTerminalVerifyError> {
        let query_count = compressed
            .input_batches
            .first()
            .map(|batch| batch.opened_values.len())
            .or_else(|| {
                compressed
                    .commit_rounds
                    .first()
                    .map(|round| round.sibling_values.len())
            })
            .unwrap_or(0);
        let restored_input_paths = compressed
            .input_batches
            .iter()
            .map(|batch| {
                if batch.opened_values.len() != query_count {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                            label: "terminal_compressed_fri_input_openings".into(),
                            expected: query_count,
                            got: batch.opened_values.len(),
                        },
                    );
                }
                Self::terminal_restore_binary_merkle_paths(&batch.pruned_opening_proof)
            })
            .collect::<Result<Vec<_>, _>>()?;
        let restored_commit_paths = compressed
            .commit_rounds
            .iter()
            .map(|round| {
                if round.sibling_values.len() != query_count {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                            label: "terminal_compressed_fri_commit_openings".into(),
                            expected: query_count,
                            got: round.sibling_values.len(),
                        },
                    );
                }
                Self::terminal_restore_binary_merkle_paths(&round.pruned_opening_proof)
            })
            .collect::<Result<Vec<_>, _>>()?;

        let mut query_proofs = Vec::with_capacity(query_count);
        for query in 0..query_count {
            let input_proof = compressed
                .input_batches
                .iter()
                .zip(&restored_input_paths)
                .map(|(batch, paths)| {
                    BatchOpening::<Goldilocks, TerminalFriValMmcs>::new(
                        batch.opened_values[query].clone(),
                        paths[query].clone(),
                    )
                })
                .collect::<Vec<_>>();
            let commit_phase_openings = compressed
                .commit_rounds
                .iter()
                .zip(&restored_commit_paths)
                .map(|(round, paths)| CommitPhaseProofStep::<
                    TerminalFriChallenge,
                    TerminalFriChallengeMmcs,
                > {
                    log_arity: round.log_arity,
                    sibling_values: round.sibling_values[query].clone(),
                    opening_proof: paths[query].clone(),
                })
                .collect::<Vec<_>>();
            query_proofs.push(QueryProof::<
                TerminalFriChallenge,
                TerminalFriChallengeMmcs,
                TerminalFriInputProof,
            > {
                input_proof,
                commit_phase_openings,
            });
        }

        Ok(FriProof::<
            TerminalFriChallenge,
            TerminalFriChallengeMmcs,
            Goldilocks,
            TerminalFriInputProof,
        > {
            commit_phase_commits: compressed.commit_phase_commits.clone(),
            commit_pow_witnesses: compressed.commit_pow_witnesses.clone(),
            query_proofs,
            final_poly: compressed.final_poly.clone(),
            query_pow_witness: compressed.query_pow_witness,
        })
    }

    pub fn compress_terminal_npo_polynomial_fri_opening_proof(
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoPolynomialFriOpeningProof,
    ) -> Result<TerminalCompressedFriProof, NativeTerminalVerifyError> {
        if proof.profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.profile.proximity.proof_parameters(),
                },
            );
        }
        Ok(proof.proof.clone())
    }

    pub fn derive_terminal_fri_query_indices_from_challenger(
        challenger: &mut TerminalFriChallenger,
        proof: &TerminalFriProof,
        profile: TerminalProximityProfile,
    ) -> Result<Vec<usize>, NativeTerminalVerifyError> {
        let log_arities = proof
            .query_proofs
            .first()
            .map(|query| {
                query
                    .commit_phase_openings
                    .iter()
                    .map(|opening| opening.log_arity as usize)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let log_global_max_height = log_arities.iter().sum::<usize>()
            + profile.log_blowup as usize
            + profile.log_final_poly_len as usize;

        let _: TerminalFriChallenge = challenger.sample_algebra_element();
        for (commitment, witness) in proof
            .commit_phase_commits
            .iter()
            .zip(&proof.commit_pow_witnesses)
        {
            challenger.observe(commitment.clone());
            if !challenger.check_witness(0, *witness) {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal FRI commit PoW witness rejected".into(),
                    },
                );
            }
            let _: TerminalFriChallenge = challenger.sample_algebra_element();
        }
        challenger.observe_algebra_slice(&proof.final_poly);
        for &log_arity in &log_arities {
            challenger.observe(Goldilocks::from_usize(log_arity));
        }
        if !challenger.check_witness(profile.query_pow_bits as usize, proof.query_pow_witness) {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal FRI query PoW witness rejected".into(),
                },
            );
        }
        Ok((0..proof.query_proofs.len())
            .map(|_| challenger.sample_bits(log_global_max_height))
            .collect())
    }

    fn terminal_prune_binary_merkle_paths(
        paths: &[(usize, Vec<[Goldilocks; 5]>)],
    ) -> Result<TerminalPrunedMerklePaths, NativeTerminalVerifyError> {
        if paths.is_empty() {
            return Ok(TerminalPrunedMerklePaths::default());
        }
        let mut order = (0..paths.len()).collect::<Vec<_>>();
        order.sort_unstable_by_key(|&index| paths[index].0);
        let mut original_order = vec![0u32; paths.len()];
        let mut unique = Vec::<usize>::new();
        for index in order {
            let leaf = paths[index].0;
            if unique
                .last()
                .is_none_or(|&prev_index| paths[prev_index].0 != leaf)
            {
                unique.push(index);
            } else if paths[*unique.last().expect("unique path exists")].1 != paths[index].1 {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI duplicate leaf has different path".into(),
                    },
                );
            }
            original_order[index] = (unique.len() - 1) as u32;
        }
        let mut pruned = Vec::with_capacity(unique.len());
        let mut previous_leaf = 0usize;
        for (slot, &index) in unique.iter().enumerate() {
            let (leaf, siblings) = &paths[index];
            let keep = if slot == 0 {
                siblings.len()
            } else {
                Self::terminal_binary_first_shared_level(previous_leaf, *leaf, siblings.len())
            };
            pruned.push(TerminalPrunedMerklePath {
                leaf_index: *leaf,
                siblings: siblings[..keep].to_vec(),
            });
            previous_leaf = *leaf;
        }
        Ok(TerminalPrunedMerklePaths {
            original_order,
            paths: pruned,
        })
    }

    fn terminal_restore_binary_merkle_paths(
        pruned: &TerminalPrunedMerklePaths,
    ) -> Result<Vec<Vec<[Goldilocks; 5]>>, NativeTerminalVerifyError> {
        if pruned.paths.is_empty() {
            return if pruned.original_order.is_empty() {
                Ok(Vec::new())
            } else {
                Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI has original-order entries but no paths"
                            .into(),
                    },
                )
            };
        }
        let full_len = pruned.paths[0].siblings.len();
        let mut sorted_full = Vec::<Vec<[Goldilocks; 5]>>::with_capacity(pruned.paths.len());
        for (slot, path) in pruned.paths.iter().enumerate() {
            if slot > 0 && pruned.paths[slot - 1].leaf_index >= path.leaf_index {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI paths are not strictly sorted".into(),
                    },
                );
            }
            if path.siblings.len() > full_len {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI path exceeds full path length".into(),
                    },
                );
            }
            let mut restored = path.siblings.clone();
            if slot > 0 {
                restored.extend_from_slice(&sorted_full[slot - 1][path.siblings.len()..]);
            }
            if restored.len() != full_len {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI path restore length mismatch".into(),
                    },
                );
            }
            sorted_full.push(restored);
        }
        pruned
            .original_order
            .iter()
            .map(|&slot| {
                sorted_full.get(slot as usize).cloned().ok_or_else(|| {
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                        reason: "terminal compressed FRI original-order slot out of range".into(),
                    }
                })
            })
            .collect()
    }

    fn terminal_binary_first_shared_level(a: usize, b: usize, num_levels: usize) -> usize {
        let xor = a ^ b;
        if xor == 0 {
            return 1.min(num_levels);
        }
        ((usize::BITS - xor.leading_zeros()) as usize).min(num_levels)
    }

    pub fn prove_terminal_npo_polynomial_fri_opening_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<TerminalNpoPolynomialFriOpeningProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.prove_terminal_npo_polynomial_fri_opening_for_column_set_goldilocks(
            verifying_key,
            public_inputs,
            witness,
            prelude,
            TerminalNpoPolynomialFriColumnSet::FullTable,
        )
    }

    pub fn prove_terminal_npo_polynomial_value_fri_opening_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<TerminalNpoPolynomialFriOpeningProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.prove_terminal_npo_polynomial_fri_opening_for_column_set_goldilocks(
            verifying_key,
            public_inputs,
            witness,
            prelude,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
        )
    }

    fn prove_terminal_npo_polynomial_fri_opening_for_column_set_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
        column_set: TerminalNpoPolynomialFriColumnSet,
    ) -> Result<TerminalNpoPolynomialFriOpeningProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let columns = self.terminal_npo_polynomial_columns_goldilocks(verifying_key, witness)?;
        Self::prove_terminal_npo_polynomial_fri_opening_from_columns_goldilocks(
            prelude, &columns, column_set,
        )
    }

    fn prove_terminal_npo_polynomial_fri_opening_from_columns_goldilocks<F>(
        prelude: &TerminalProofPrelude,
        columns: &TerminalNpoPolynomialColumns<F>,
        column_set: TerminalNpoPolynomialFriColumnSet,
    ) -> Result<TerminalNpoPolynomialFriOpeningProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let (profile, matrix) =
            Self::terminal_npo_polynomial_basis_matrix_for_column_set_goldilocks(
                columns, column_set,
            )?;
        if profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: profile.proximity.proof_parameters(),
                },
            );
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(profile.proximity)?;
        Self::seed_terminal_npo_polynomial_fri_challenger(&mut challenger, prelude, &profile);
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                profile.padded_rows,
            );
        let (commitment, data) = <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::commit(&pcs, [(domain, matrix)]);
        challenger.observe(commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let (opened_values, plain_proof) = <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::open(
            &pcs, vec![(&data, vec![vec![zeta]])], &mut challenger
        );
        let opened_values_flat = opened_values
            .first()
            .and_then(|round| round.first())
            .and_then(|matrix| matrix.first())
            .ok_or(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty)?
            .clone();
        let opened_values_basis = opened_values_flat
            .iter()
            .map(Self::goldilocks_basis_u64)
            .collect();
        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_npo_polynomial_fri_challenger(
            &mut query_challenger,
            prelude,
            &profile,
        );
        query_challenger.observe(commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe_algebra_slice(&opened_values_flat);
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;

        Ok(TerminalNpoPolynomialFriOpeningProof {
            profile,
            commitment,
            opened_values_basis,
            proof,
        })
    }

    pub fn prove_terminal_npo_polynomial_padding_quotient_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<TerminalNpoPolynomialPaddingQuotientProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let columns = self.terminal_npo_polynomial_columns_goldilocks(verifying_key, witness)?;
        let verifier_columns =
            self.terminal_npo_polynomial_verifier_derived_columns_goldilocks(verifying_key)?;
        Self::prove_terminal_npo_polynomial_padding_quotient_from_columns_goldilocks(
            prelude,
            &columns,
            &verifier_columns,
        )
    }

    fn prove_terminal_npo_polynomial_padding_quotient_from_columns_goldilocks<F>(
        prelude: &TerminalProofPrelude,
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<TerminalNpoPolynomialPaddingQuotientProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let (value_profile, value_matrix) =
            Self::terminal_npo_polynomial_value_basis_matrix_goldilocks(&columns)?;
        if value_profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: value_profile.proximity.proof_parameters(),
                },
            );
        }
        let quotient_profile =
            Self::terminal_npo_polynomial_padding_quotient_profile(&columns.layout)?;
        if quotient_profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: quotient_profile.proximity.proof_parameters(),
                },
            );
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(value_profile.proximity)?;
        Self::seed_terminal_npo_padding_quotient_challenger(
            &mut challenger,
            prelude,
            &value_profile,
            &quotient_profile,
        );
        let value_domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                value_profile.padded_rows,
            );
        let (value_commitment, value_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(value_domain, value_matrix)],
            );
        challenger.observe(value_commitment.clone());
        let alpha: TerminalFriChallenge = challenger.sample_algebra_element();

        let quotient_domain = value_domain.create_disjoint_domain(quotient_profile.padded_rows);
        let quotient_matrix = Self::terminal_npo_polynomial_padding_quotient_matrix_goldilocks(
            value_domain,
            quotient_domain,
            &columns,
            &verifier_columns,
            alpha,
        )?;
        let (quotient_commitment, quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(quotient_domain, quotient_matrix)],
            );
        challenger.observe(quotient_commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let (opened_values, plain_proof) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::open(
                &pcs,
                vec![
                    (&value_data, vec![vec![zeta]]),
                    (&quotient_data, vec![vec![zeta]]),
                ],
                &mut challenger,
            );
        let opened_value_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 0)?;
        let opened_quotient_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 1)?;
        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_npo_padding_quotient_challenger(
            &mut query_challenger,
            prelude,
            &value_profile,
            &quotient_profile,
        );
        query_challenger.observe(value_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(quotient_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        for point_values in &opened_values[0][0] {
            query_challenger.observe_algebra_slice(point_values);
        }
        for point_values in &opened_values[1][0] {
            query_challenger.observe_algebra_slice(point_values);
        }
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            value_profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;

        Ok(TerminalNpoPolynomialPaddingQuotientProof {
            value_profile,
            quotient_profile,
            value_commitment,
            quotient_commitment,
            opened_value_basis,
            opened_quotient_basis,
            proof,
        })
    }

    fn terminal_npo_polynomial_padding_quotient_matrix_goldilocks<F>(
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        alpha: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let value_profile = Self::terminal_npo_polynomial_fri_profile_for_column_count::<F>(
            &columns.layout,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
            Self::terminal_npo_polynomial_fri_column_indices(
                columns,
                TerminalNpoPolynomialFriColumnSet::WitnessValues,
            )?
            .len(),
        )?;
        let constraints = Self::terminal_npo_polynomial_value_quotient_constraints(
            columns,
            verifier_columns,
            &value_profile,
        )?;
        let mut quotient_values = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            let mut folded = TerminalFriChallenge::ZERO;
            let mut coeff = TerminalFriChallenge::ONE;
            for constraint in &constraints {
                let selector =
                    value_domain.evaluate_polynomial_at(&constraint.selector_evals, point);
                let value = value_domain.evaluate_polynomial_at(&constraint.value_evals, point);
                let rhs = constraint
                    .rhs_evals
                    .as_ref()
                    .map(|rhs_evals| value_domain.evaluate_polynomial_at(rhs_evals, point));
                folded += coeff
                    * Self::terminal_npo_value_quotient_constraint_value(
                        constraint.kind,
                        selector,
                        value,
                        rhs,
                    );
                coeff *= alpha;
            }
            let z_h = value_domain.vanishing_poly_at_point(point);
            quotient_values.push(folded / z_h);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal NPO padding quotient domain has no successor".into(),
                }
            })?;
        }
        Ok(RowMajorMatrix::new_col(quotient_values).flatten_to_base())
    }

    fn terminal_npo_polynomial_value_quotient_constraints<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
    ) -> Result<Vec<TerminalNpoValueQuotientConstraint>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        Self::validate_terminal_npo_polynomial_columns(&verifier_columns.layout, verifier_columns)?;
        if verifier_columns.layout != columns.layout || verifier_columns.labels != columns.labels {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLayoutMismatch {
                    expected: columns.layout.clone(),
                    got: verifier_columns.layout.clone(),
                },
            );
        }
        let value_indices = Self::terminal_npo_polynomial_fri_column_indices(
            columns,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
        )?;
        let mut constraints =
            Vec::with_capacity(value_indices.len() * profile.field_basis_dimension);
        for value_column_index in value_indices {
            let label = &columns.labels[value_column_index];
            let present_label = Self::terminal_npo_polynomial_value_present_label(label).ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: label.clone(),
                },
            )?;
            let present_column_index = verifier_columns
                .labels
                .iter()
                .position(|candidate| candidate == &present_label)
                .ok_or_else(
                    || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                        label: present_label.clone(),
                    },
                )?;
            let present_evals = Self::terminal_npo_polynomial_column_basis_evals(
                verifier_columns,
                profile,
                present_column_index,
                0,
            );
            for basis_index in 0..profile.field_basis_dimension {
                let value_evals = Self::terminal_npo_polynomial_column_basis_evals(
                    columns,
                    profile,
                    value_column_index,
                    basis_index,
                );
                constraints.push(TerminalNpoValueQuotientConstraint {
                    selector_evals: present_evals.clone(),
                    value_evals,
                    rhs_evals: None,
                    kind: TerminalNpoValueQuotientConstraintKind::Padding,
                });
            }
            if label == "mmcs_bit" {
                for basis_index in 0..profile.field_basis_dimension {
                    let value_evals = Self::terminal_npo_polynomial_column_basis_evals(
                        columns,
                        profile,
                        value_column_index,
                        basis_index,
                    );
                    let kind = if basis_index == 0 {
                        TerminalNpoValueQuotientConstraintKind::MmcsBooleanBase
                    } else {
                        TerminalNpoValueQuotientConstraintKind::MmcsBooleanTail
                    };
                    constraints.push(TerminalNpoValueQuotientConstraint {
                        selector_evals: present_evals.clone(),
                        value_evals,
                        rhs_evals: None,
                        kind,
                    });
                }
            }
        }
        Self::append_terminal_npo_tip5_new_start_zero_quotient_constraints(
            columns,
            verifier_columns,
            profile,
            &mut constraints,
        )?;
        Self::append_terminal_npo_tip5_capacity_zero_quotient_constraints(
            columns,
            verifier_columns,
            profile,
            &mut constraints,
        )?;
        Self::append_terminal_npo_recompose_value_quotient_constraints(
            columns,
            verifier_columns,
            profile,
            &mut constraints,
        )?;
        Ok(constraints)
    }

    fn append_terminal_npo_tip5_new_start_zero_quotient_constraints<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        constraints: &mut Vec<TerminalNpoValueQuotientConstraint>,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        for limb in 0..16 {
            let hidden_label = format!("hidden_tip5_value_{limb}");
            let present_label = format!("hidden_tip5_present_{limb}");
            if !columns.labels.iter().any(|label| label == &hidden_label) {
                continue;
            }

            let mut selector_sets = Vec::with_capacity(2);
            selector_sets.push(Self::terminal_npo_polynomial_mixed_product_selector_evals(
                verifier_columns,
                profile,
                &["is_tip5", "mode_new_start", &present_label],
                &["mode_merkle_path"],
            )?);
            if limb < 5 {
                selector_sets.push(Self::terminal_npo_polynomial_product_selector_evals(
                    verifier_columns,
                    profile,
                    &[
                        "is_tip5",
                        "mode_new_start",
                        "mode_merkle_path",
                        &present_label,
                    ],
                )?);
            }

            let hidden_column = Self::terminal_npo_polynomial_column_index(columns, &hidden_label)?;
            for selector_evals in selector_sets {
                if selector_evals
                    .iter()
                    .all(|value| *value == Goldilocks::ZERO)
                {
                    continue;
                }
                for basis_index in 0..profile.field_basis_dimension {
                    constraints.push(TerminalNpoValueQuotientConstraint {
                        selector_evals: selector_evals.clone(),
                        value_evals: Self::terminal_npo_polynomial_column_basis_evals(
                            columns,
                            profile,
                            hidden_column,
                            basis_index,
                        ),
                        rhs_evals: None,
                        kind: TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                    });
                }
            }
        }
        Ok(())
    }

    fn append_terminal_npo_tip5_capacity_zero_quotient_constraints<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        constraints: &mut Vec<TerminalNpoValueQuotientConstraint>,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        for limb in 10..16 {
            let hidden_label = format!("hidden_tip5_value_{limb}");
            let present_label = format!("hidden_tip5_present_{limb}");
            if !columns.labels.iter().any(|label| label == &hidden_label) {
                continue;
            }
            let selector_evals = Self::terminal_npo_polynomial_product_selector_evals(
                verifier_columns,
                profile,
                &["is_tip5", "mode_merkle_path", &present_label],
            )?;
            if selector_evals
                .iter()
                .all(|value| *value == Goldilocks::ZERO)
            {
                continue;
            }
            let hidden_column = Self::terminal_npo_polynomial_column_index(columns, &hidden_label)?;
            for basis_index in 0..profile.field_basis_dimension {
                constraints.push(TerminalNpoValueQuotientConstraint {
                    selector_evals: selector_evals.clone(),
                    value_evals: Self::terminal_npo_polynomial_column_basis_evals(
                        columns,
                        profile,
                        hidden_column,
                        basis_index,
                    ),
                    rhs_evals: None,
                    kind: TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                });
            }
        }
        Ok(())
    }

    fn append_terminal_npo_recompose_value_quotient_constraints<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        constraints: &mut Vec<TerminalNpoValueQuotientConstraint>,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let selector_evals = Self::terminal_npo_polynomial_combined_selector_evals(
            verifier_columns,
            profile,
            &["is_recompose", "is_recompose_coeff"],
        )?;
        let selector_is_zero = selector_evals
            .iter()
            .all(|value| *value == Goldilocks::ZERO);
        if selector_is_zero {
            return Ok(());
        }
        let output_column = Self::terminal_npo_polynomial_column_index(columns, "output_value_0")?;
        for basis_index in 0..profile.field_basis_dimension {
            let input_label = format!("input_value_{basis_index}");
            let input_column = Self::terminal_npo_polynomial_column_index(columns, &input_label)?;
            for tail_basis in 1..profile.field_basis_dimension {
                constraints.push(TerminalNpoValueQuotientConstraint {
                    selector_evals: selector_evals.clone(),
                    value_evals: Self::terminal_npo_polynomial_column_basis_evals(
                        columns,
                        profile,
                        input_column,
                        tail_basis,
                    ),
                    rhs_evals: None,
                    kind: TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                });
            }
            constraints.push(TerminalNpoValueQuotientConstraint {
                selector_evals: selector_evals.clone(),
                value_evals: Self::terminal_npo_polynomial_column_basis_evals(
                    columns,
                    profile,
                    output_column,
                    basis_index,
                ),
                rhs_evals: Some(Self::terminal_npo_polynomial_column_basis_evals(
                    columns,
                    profile,
                    input_column,
                    0,
                )),
                kind: TerminalNpoValueQuotientConstraintKind::SelectorTimesDifference,
            });
        }
        Ok(())
    }

    fn terminal_npo_polynomial_column_index<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        label: &str,
    ) -> Result<usize, NativeTerminalVerifyError> {
        columns
            .labels
            .iter()
            .position(|candidate| candidate == label)
            .ok_or_else(
                || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                    label: label.into(),
                },
            )
    }

    fn terminal_npo_polynomial_column_basis_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        column_index: usize,
        basis_index: usize,
    ) -> Vec<Goldilocks>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut evals = Vec::with_capacity(profile.padded_rows);
        for row in 0..profile.padded_rows {
            let value = if row < profile.rows {
                columns.columns[column_index][row]
                    .as_basis_coefficients_slice()
                    .get(basis_index)
                    .copied()
                    .unwrap_or(Goldilocks::ZERO)
            } else {
                Goldilocks::ZERO
            };
            evals.push(value);
        }
        evals
    }

    fn terminal_npo_polynomial_combined_selector_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        labels: &[&str],
    ) -> Result<Vec<Goldilocks>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut combined = vec![Goldilocks::ZERO; profile.padded_rows];
        for label in labels {
            let index = Self::terminal_npo_polynomial_column_index(columns, label)?;
            let evals =
                Self::terminal_npo_polynomial_column_basis_evals(columns, profile, index, 0);
            for (acc, value) in combined.iter_mut().zip(evals) {
                *acc += value;
            }
        }
        Ok(combined)
    }

    fn terminal_npo_polynomial_mixed_product_selector_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        labels: &[&str],
        one_minus_labels: &[&str],
    ) -> Result<Vec<Goldilocks>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut combined =
            Self::terminal_npo_polynomial_product_selector_evals(columns, profile, labels)?;
        for label in one_minus_labels {
            let index = Self::terminal_npo_polynomial_column_index(columns, label)?;
            let evals =
                Self::terminal_npo_polynomial_column_basis_evals(columns, profile, index, 0);
            for (acc, value) in combined.iter_mut().zip(evals) {
                *acc *= Goldilocks::ONE - value;
            }
        }
        Ok(combined)
    }

    fn terminal_npo_polynomial_product_selector_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        profile: &TerminalNpoPolynomialFriProfile,
        labels: &[&str],
    ) -> Result<Vec<Goldilocks>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut combined = vec![Goldilocks::ONE; profile.padded_rows];
        for label in labels {
            let index = Self::terminal_npo_polynomial_column_index(columns, label)?;
            let evals =
                Self::terminal_npo_polynomial_column_basis_evals(columns, profile, index, 0);
            for (acc, value) in combined.iter_mut().zip(evals) {
                *acc *= value;
            }
        }
        Ok(combined)
    }

    fn terminal_npo_value_quotient_constraint_value(
        kind: TerminalNpoValueQuotientConstraintKind,
        selector: TerminalFriChallenge,
        value: TerminalFriChallenge,
        rhs: Option<TerminalFriChallenge>,
    ) -> TerminalFriChallenge {
        match kind {
            TerminalNpoValueQuotientConstraintKind::Padding => {
                (TerminalFriChallenge::ONE - selector) * value
            }
            TerminalNpoValueQuotientConstraintKind::MmcsBooleanBase => {
                selector * value * (value - TerminalFriChallenge::ONE)
            }
            TerminalNpoValueQuotientConstraintKind::MmcsBooleanTail => selector * value,
            TerminalNpoValueQuotientConstraintKind::SelectorTimesValue => selector * value,
            TerminalNpoValueQuotientConstraintKind::SelectorTimesDifference => {
                selector * (value - rhs.unwrap_or(TerminalFriChallenge::ZERO))
            }
        }
    }

    fn terminal_npo_opened_matrix_basis_u64(
        opened_values: &[Vec<Vec<Vec<TerminalFriChallenge>>>],
        matrix_index: usize,
    ) -> Result<Vec<Vec<u64>>, NativeTerminalVerifyError> {
        Ok(opened_values
            .get(matrix_index)
            .and_then(|round| round.first())
            .and_then(|matrix| matrix.first())
            .ok_or(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty)?
            .iter()
            .map(Self::goldilocks_basis_u64)
            .collect::<Vec<_>>())
    }

    fn terminal_npo_opened_matrix_points_basis_u64(
        opened_values: &[Vec<Vec<Vec<TerminalFriChallenge>>>],
        matrix_index: usize,
    ) -> Result<Vec<Vec<Vec<u64>>>, NativeTerminalVerifyError> {
        Ok(opened_values
            .get(matrix_index)
            .and_then(|round| round.first())
            .ok_or(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty)?
            .iter()
            .map(|point| point.iter().map(Self::goldilocks_basis_u64).collect())
            .collect::<Vec<_>>())
    }

    fn terminal_compact_composition_matrix_from_goldilocks_values(
        values: &[Goldilocks],
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if values.len() != profile.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_values".into(),
                    expected: profile.rows,
                    got: values.len(),
                },
            );
        }
        let expected_basis_columns =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        if profile.basis_columns != expected_basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_basis_columns".into(),
                    expected: expected_basis_columns,
                    got: profile.basis_columns,
                },
            );
        }
        let mut matrix_values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        for (row, value) in values.iter().copied().enumerate() {
            matrix_values[row * profile.basis_columns] = value;
        }
        Ok(RowMajorMatrix::new(matrix_values, profile.basis_columns))
    }

    fn terminal_compact_composition_point_values_from_basis(
        basis: &[Vec<u64>],
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<Vec<TerminalFriChallenge>, NativeTerminalVerifyError> {
        if basis.len() != profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: profile.basis_columns,
                    got: basis.len(),
                },
            );
        }
        basis
            .iter()
            .map(|value_basis| {
                Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(value_basis)
            })
            .collect()
    }

    fn terminal_compact_composition_row_point(
        domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        row: usize,
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        if row >= profile.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_row_point".into(),
                    expected: profile.rows,
                    got: row + 1,
                },
            );
        }
        let mut point = TerminalFriChallenge::from(domain.first_point());
        for _ in 0..row {
            point = domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal compact composition row point outside domain".into(),
                }
            })?;
        }
        Ok(point)
    }

