    fn verify_and_open_terminal_npo_tip5_lookup_fri_opening_for_column_set_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoTip5LookupFriOpeningProof,
        column_set: TerminalNpoTip5LookupFriColumnSet,
    ) -> Result<TerminalNpoTip5LookupFriOpenedColumns, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let trace_profile = Self::terminal_npo_tip5_lookup_trace_profile(verifying_key);
        let expected_profile =
            Self::terminal_npo_tip5_lookup_fri_profile_for_column_set(&trace_profile, column_set)?;
        if proof.profile != expected_profile {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_fri_profile".into(),
                    expected: expected_profile.basis_columns,
                    got: proof.profile.basis_columns,
                },
            );
        }
        if proof.profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.profile.proximity.proof_parameters(),
                },
            );
        }
        if proof.opened_values_basis.len() != proof.profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.profile.basis_columns,
                    got: proof.opened_values_basis.len(),
                },
            );
        }
        let mut opened_values = Vec::with_capacity(proof.opened_values_basis.len());
        for basis in &proof.opened_values_basis {
            opened_values
                .push(Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(basis)?);
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(proof.profile.proximity)?;
        Self::seed_terminal_npo_tip5_lookup_fri_challenger(&mut challenger, prelude, &proof.profile);
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                proof.profile.padded_rows,
            );
        challenger.observe(proof.commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::verify(
            &pcs,
            vec![(
                proof.commitment.clone(),
                vec![(domain, vec![(zeta, opened_values.clone())])],
            )],
            &proof.proof,
            &mut challenger,
        )
        .map_err(|err| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: format!("terminal Tip5 lookup FRI verification failed: {err:?}"),
            }
        })?;

        Ok(TerminalNpoTip5LookupFriOpenedColumns {
            profile: proof.profile.clone(),
            zeta,
            labels: Self::terminal_npo_tip5_lookup_fri_column_labels(&proof.profile)?,
            values: opened_values,
        })
    }

    pub fn verify_terminal_npo_polynomial_value_padding_opening_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoPolynomialFriOpeningProof,
    ) -> Result<TerminalNpoPolynomialFriOpenedColumns, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let opened = self
            .verify_and_open_terminal_npo_polynomial_value_fri_opening_goldilocks::<F>(
                verifying_key,
                public_inputs,
                prelude,
                proof,
            )?;
        let verifier_columns =
            self.terminal_npo_polynomial_verifier_derived_columns_goldilocks(verifying_key)?;
        for (label, value_basis) in opened.labels.iter().zip(&opened.values) {
            let present_label = Self::terminal_npo_polynomial_value_present_label(label).ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: label.clone(),
                },
            )?;
            let present_column_index = verifier_columns
                .labels
                .iter()
                .position(|candidate| candidate == &present_label)
                .ok_or_else(
                    || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                        label: present_label.clone(),
                    },
                )?;
            let present_column = &verifier_columns.columns[present_column_index];
            let present_is_never = present_column.iter().all(|value| *value == F::ZERO);
            let present_is_always = present_column.iter().all(|value| *value == F::ONE);
            if present_is_always {
                continue;
            }
            if !present_is_never {
                continue;
            }
            for value in value_basis {
                if *value != TerminalFriChallenge::ZERO {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                            label: label.clone(),
                        },
                    );
                }
            }
        }
        Ok(opened)
    }

    pub fn verify_terminal_npo_polynomial_padding_quotient_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoPolynomialPaddingQuotientProof,
    ) -> Result<TerminalNpoPolynomialFriOpenedColumns, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let layout = Self::terminal_npo_polynomial_column_layout::<F>(verifying_key);
        let labels = Self::terminal_npo_polynomial_column_labels(&layout);
        let dummy_columns = TerminalNpoPolynomialColumns::<F> {
            layout: layout.clone(),
            labels: labels.clone(),
            columns: vec![Vec::new(); layout.column_count],
        };
        let value_column_indices = Self::terminal_npo_polynomial_fri_column_indices(
            &dummy_columns,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
        )?;
        let opened_labels = value_column_indices
            .iter()
            .map(|index| labels[*index].clone())
            .collect::<Vec<_>>();
        let expected_value_profile = Self::terminal_npo_polynomial_fri_profile_for_column_count::<F>(
            &layout,
            TerminalNpoPolynomialFriColumnSet::WitnessValues,
            value_column_indices.len(),
        )?;
        let expected_quotient_profile =
            Self::terminal_npo_polynomial_padding_quotient_profile(&layout)?;
        if proof.value_profile != expected_value_profile {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_padding_value_profile".into(),
                    expected: expected_value_profile.basis_columns,
                    got: proof.value_profile.basis_columns,
                },
            );
        }
        if proof.quotient_profile != expected_quotient_profile {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_padding_quotient_profile".into(),
                    expected: expected_quotient_profile.basis_columns,
                    got: proof.quotient_profile.basis_columns,
                },
            );
        }
        if proof.value_profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.value_profile.proximity.proof_parameters(),
                },
            );
        }
        if proof.quotient_profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.quotient_profile.proximity.proof_parameters(),
                },
            );
        }
        if proof.opened_value_basis.len() != proof.value_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.value_profile.basis_columns,
                    got: proof.opened_value_basis.len(),
                },
            );
        }
        if proof.opened_quotient_basis.len() != proof.quotient_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.quotient_profile.basis_columns,
                    got: proof.opened_quotient_basis.len(),
                },
            );
        }

        let mut opened_value_flat = Vec::with_capacity(proof.opened_value_basis.len());
        for basis in &proof.opened_value_basis {
            opened_value_flat
                .push(Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(basis)?);
        }
        let mut opened_quotient_flat = Vec::with_capacity(proof.opened_quotient_basis.len());
        for basis in &proof.opened_quotient_basis {
            opened_quotient_flat
                .push(Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(basis)?);
        }

        let (pcs, mut challenger) =
            Self::terminal_fri_pcs_and_challenger(proof.value_profile.proximity)?;
        Self::seed_terminal_npo_padding_quotient_challenger(
            &mut challenger,
            prelude,
            &proof.value_profile,
            &proof.quotient_profile,
        );
        let value_domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                proof.value_profile.padded_rows,
            );
        let quotient_domain =
            value_domain.create_disjoint_domain(proof.quotient_profile.padded_rows);
        challenger.observe(proof.value_commitment.clone());
        let alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        challenger.observe(proof.quotient_commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let restored = Self::decompress_terminal_fri_proof(&proof.proof)?;
        <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::verify(
            &pcs,
            vec![
                (
                    proof.value_commitment.clone(),
                    vec![(value_domain, vec![(zeta, opened_value_flat.clone())])],
                ),
                (
                    proof.quotient_commitment.clone(),
                    vec![(quotient_domain, vec![(zeta, opened_quotient_flat.clone())])],
                ),
            ],
            &restored,
            &mut challenger,
        )
        .map_err(|err| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: format!("terminal NPO padding quotient FRI verification failed: {err:?}"),
            }
        })?;

        let mut opened_values = Vec::with_capacity(proof.value_profile.field_columns);
        let mut offset = 0usize;
        for _ in 0..proof.value_profile.field_columns {
            let next_offset = offset + proof.value_profile.field_basis_dimension;
            opened_values.push(opened_value_flat[offset..next_offset].to_vec());
            offset = next_offset;
        }

        let quotient =
            <TerminalFriChallenge as ExtensionField<Goldilocks>>::from_ext_basis_coefficients(
                &opened_quotient_flat,
            )
            .ok_or(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.quotient_profile.field_basis_dimension,
                    got: opened_quotient_flat.len(),
                },
            )?;
        let verifier_columns =
            self.terminal_npo_polynomial_verifier_derived_columns_goldilocks(verifying_key)?;
        let opened = TerminalNpoPolynomialFriOpenedColumns {
            profile: proof.value_profile.clone(),
            zeta,
            labels: opened_labels,
            values: opened_values,
        };
        self.verify_terminal_npo_padding_quotient_identity_goldilocks(
            &verifier_columns,
            value_domain,
            alpha,
            quotient,
            &opened,
        )?;
        Ok(opened)
    }

    fn verify_terminal_npo_padding_quotient_identity_goldilocks<F>(
        &self,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        alpha: TerminalFriChallenge,
        quotient: TerminalFriChallenge,
        opened: &TerminalNpoPolynomialFriOpenedColumns,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        for (label, value_basis) in opened.labels.iter().zip(&opened.values) {
            let present_label = Self::terminal_npo_polynomial_value_present_label(label).ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: label.clone(),
                },
            )?;
            let present_column_index = verifier_columns
                .labels
                .iter()
                .position(|candidate| candidate == &present_label)
                .ok_or_else(
                    || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                        label: present_label.clone(),
                    },
                )?;
            let mut present_evals = Vec::with_capacity(opened.profile.padded_rows);
            for row in 0..opened.profile.padded_rows {
                let present = if row < opened.profile.rows {
                    verifier_columns.columns[present_column_index][row]
                        .as_basis_coefficients_slice()
                        .first()
                        .copied()
                        .unwrap_or(Goldilocks::ZERO)
                } else {
                    Goldilocks::ZERO
                };
                present_evals.push(present);
            }
            let present = value_domain.evaluate_polynomial_at(&present_evals, opened.zeta);
            for value in value_basis {
                folded += coeff
                    * Self::terminal_npo_value_quotient_constraint_value(
                        TerminalNpoValueQuotientConstraintKind::Padding,
                        present,
                        *value,
                        None,
                    );
                coeff *= alpha;
            }
            if label == "mmcs_bit" {
                for (basis_index, value) in value_basis.iter().enumerate() {
                    let kind = if basis_index == 0 {
                        TerminalNpoValueQuotientConstraintKind::MmcsBooleanBase
                    } else {
                        TerminalNpoValueQuotientConstraintKind::MmcsBooleanTail
                    };
                    folded += coeff
                        * Self::terminal_npo_value_quotient_constraint_value(
                            kind, present, *value, None,
                        );
                    coeff *= alpha;
                }
            }
        }
        self.fold_terminal_npo_tip5_new_start_zero_quotient_identity_goldilocks(
            verifier_columns,
            value_domain,
            alpha,
            opened,
            &mut folded,
            &mut coeff,
        )?;
        self.fold_terminal_npo_tip5_capacity_zero_quotient_identity_goldilocks(
            verifier_columns,
            value_domain,
            alpha,
            opened,
            &mut folded,
            &mut coeff,
        )?;
        self.fold_terminal_npo_recompose_value_quotient_identity_goldilocks(
            verifier_columns,
            value_domain,
            alpha,
            opened,
            &mut folded,
            &mut coeff,
        )?;
        let expected = quotient * value_domain.vanishing_poly_at_point(opened.zeta);
        if folded != expected {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: "npo_value_relation_quotient".into(),
                },
            );
        }
        Ok(())
    }

    fn fold_terminal_npo_tip5_new_start_zero_quotient_identity_goldilocks<F>(
        &self,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        alpha: TerminalFriChallenge,
        opened: &TerminalNpoPolynomialFriOpenedColumns,
        folded: &mut TerminalFriChallenge,
        coeff: &mut TerminalFriChallenge,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        for limb in 0..16 {
            let hidden_label = format!("hidden_tip5_value_{limb}");
            if !opened.labels.iter().any(|label| label == &hidden_label) {
                continue;
            }
            let present_label = format!("hidden_tip5_present_{limb}");
            let mut selector_sets = Vec::with_capacity(2);
            selector_sets.push(Self::terminal_npo_polynomial_mixed_product_selector_evals(
                verifier_columns,
                &opened.profile,
                &["is_tip5", "mode_new_start", &present_label],
                &["mode_merkle_path"],
            )?);
            if limb < 5 {
                selector_sets.push(Self::terminal_npo_polynomial_product_selector_evals(
                    verifier_columns,
                    &opened.profile,
                    &[
                        "is_tip5",
                        "mode_new_start",
                        "mode_merkle_path",
                        &present_label,
                    ],
                )?);
            }
            let hidden_basis = Self::terminal_npo_opened_value_basis(opened, &hidden_label)?;
            for selector_evals in selector_sets {
                if selector_evals
                    .iter()
                    .all(|value| *value == Goldilocks::ZERO)
                {
                    continue;
                }
                let selector = value_domain.evaluate_polynomial_at(&selector_evals, opened.zeta);
                for value in hidden_basis {
                    *folded += *coeff
                        * Self::terminal_npo_value_quotient_constraint_value(
                            TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                            selector,
                            *value,
                            None,
                        );
                    *coeff *= alpha;
                }
            }
        }
        Ok(())
    }

    fn fold_terminal_npo_tip5_capacity_zero_quotient_identity_goldilocks<F>(
        &self,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        alpha: TerminalFriChallenge,
        opened: &TerminalNpoPolynomialFriOpenedColumns,
        folded: &mut TerminalFriChallenge,
        coeff: &mut TerminalFriChallenge,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        for limb in 10..16 {
            let hidden_label = format!("hidden_tip5_value_{limb}");
            if !opened.labels.iter().any(|label| label == &hidden_label) {
                continue;
            }
            let present_label = format!("hidden_tip5_present_{limb}");
            let selector_evals = Self::terminal_npo_polynomial_product_selector_evals(
                verifier_columns,
                &opened.profile,
                &["is_tip5", "mode_merkle_path", &present_label],
            )?;
            if selector_evals
                .iter()
                .all(|value| *value == Goldilocks::ZERO)
            {
                continue;
            }
            let selector = value_domain.evaluate_polynomial_at(&selector_evals, opened.zeta);
            let hidden_basis = Self::terminal_npo_opened_value_basis(opened, &hidden_label)?;
            for value in hidden_basis {
                *folded += *coeff
                    * Self::terminal_npo_value_quotient_constraint_value(
                        TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                        selector,
                        *value,
                        None,
                    );
                *coeff *= alpha;
            }
        }
        Ok(())
    }

    fn fold_terminal_npo_recompose_value_quotient_identity_goldilocks<F>(
        &self,
        verifier_columns: &TerminalNpoPolynomialColumns<F>,
        value_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        alpha: TerminalFriChallenge,
        opened: &TerminalNpoPolynomialFriOpenedColumns,
        folded: &mut TerminalFriChallenge,
        coeff: &mut TerminalFriChallenge,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let selector_evals = Self::terminal_npo_polynomial_combined_selector_evals(
            verifier_columns,
            &opened.profile,
            &["is_recompose", "is_recompose_coeff"],
        )?;
        if selector_evals
            .iter()
            .all(|value| *value == Goldilocks::ZERO)
        {
            return Ok(());
        }
        let selector = value_domain.evaluate_polynomial_at(&selector_evals, opened.zeta);
        let output_basis = Self::terminal_npo_opened_value_basis(opened, "output_value_0")?;
        for basis_index in 0..opened.profile.field_basis_dimension {
            let input_label = format!("input_value_{basis_index}");
            let input_basis = Self::terminal_npo_opened_value_basis(opened, &input_label)?;
            for tail_basis in 1..opened.profile.field_basis_dimension {
                let value = input_basis.get(tail_basis).copied().ok_or(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: opened.profile.field_basis_dimension,
                        got: input_basis.len(),
                    },
                )?;
                *folded += *coeff
                    * Self::terminal_npo_value_quotient_constraint_value(
                        TerminalNpoValueQuotientConstraintKind::SelectorTimesValue,
                        selector,
                        value,
                        None,
                    );
                *coeff *= alpha;
            }
            let output = output_basis.get(basis_index).copied().ok_or(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: opened.profile.field_basis_dimension,
                    got: output_basis.len(),
                },
            )?;
            let input_base = input_basis.first().copied().ok_or(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: opened.profile.field_basis_dimension,
                    got: input_basis.len(),
                },
            )?;
            *folded += *coeff
                * Self::terminal_npo_value_quotient_constraint_value(
                    TerminalNpoValueQuotientConstraintKind::SelectorTimesDifference,
                    selector,
                    output,
                    Some(input_base),
                );
            *coeff *= alpha;
        }
        Ok(())
    }

    fn terminal_npo_opened_value_basis<'a>(
        opened: &'a TerminalNpoPolynomialFriOpenedColumns,
        label: &str,
    ) -> Result<&'a Vec<TerminalFriChallenge>, NativeTerminalVerifyError> {
        opened
            .labels
            .iter()
            .position(|candidate| candidate == label)
            .map(|index| &opened.values[index])
            .ok_or_else(
                || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                    label: label.into(),
                },
            )
    }

    fn verify_terminal_npo_polynomial_fri_opening_for_column_set_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoPolynomialFriOpeningProof,
        column_set: TerminalNpoPolynomialFriColumnSet,
    ) -> Result<TerminalNpoPolynomialFriOpenedColumns, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let layout = Self::terminal_npo_polynomial_column_layout::<F>(verifying_key);
        let labels = Self::terminal_npo_polynomial_column_labels(&layout);
        let dummy_columns = TerminalNpoPolynomialColumns::<F> {
            layout: layout.clone(),
            labels: labels.clone(),
            columns: vec![Vec::new(); layout.column_count],
        };
        let column_indices =
            Self::terminal_npo_polynomial_fri_column_indices(&dummy_columns, column_set)?;
        let field_columns = column_indices.len();
        let opened_labels = column_indices
            .iter()
            .map(|index| labels[*index].clone())
            .collect::<Vec<_>>();
        let expected_profile = Self::terminal_npo_polynomial_fri_profile_for_column_count::<F>(
            &layout,
            column_set,
            field_columns,
        )?;
        if proof.profile != expected_profile {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_fri_profile".into(),
                    expected: expected_profile.basis_columns,
                    got: proof.profile.basis_columns,
                },
            );
        }
        if proof.profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: proof.profile.proximity.proof_parameters(),
                },
            );
        }
        if proof.opened_values_basis.len() != proof.profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: proof.profile.basis_columns,
                    got: proof.opened_values_basis.len(),
                },
            );
        }
        let mut opened_values = Vec::with_capacity(proof.opened_values_basis.len());
        for basis in &proof.opened_values_basis {
            opened_values
                .push(Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(basis)?);
        }

        let (pcs, mut challenger) = Self::terminal_fri_pcs_and_challenger(proof.profile.proximity)?;
        Self::seed_terminal_npo_polynomial_fri_challenger(&mut challenger, prelude, &proof.profile);
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                proof.profile.padded_rows,
            );
        challenger.observe(proof.commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let restored = Self::decompress_terminal_fri_proof(&proof.proof)?;
        <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::verify(
            &pcs,
            vec![(
                proof.commitment.clone(),
                vec![(domain, vec![(zeta, opened_values.clone())])],
            )],
            &restored,
            &mut challenger,
        )
        .map_err(|err| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: format!("terminal NPO FRI verification failed: {err:?}"),
            }
        })?;

        let mut values = Vec::with_capacity(proof.profile.field_columns);
        let mut offset = 0usize;
        for _ in 0..proof.profile.field_columns {
            let next_offset = offset + proof.profile.field_basis_dimension;
            values.push(opened_values[offset..next_offset].to_vec());
            offset = next_offset;
        }
        Ok(TerminalNpoPolynomialFriOpenedColumns {
            profile: proof.profile.clone(),
            zeta,
            labels: opened_labels,
            values,
        })
    }

    fn terminal_npo_polynomial_value_present_label(label: &str) -> Option<String> {
        label
            .strip_prefix("input_value_")
            .map(|slot| format!("input_present_{slot}"))
            .or_else(|| {
                label
                    .strip_prefix("output_value_")
                    .map(|slot| format!("output_present_{slot}"))
            })
            .or_else(|| {
                label
                    .strip_prefix("hidden_tip5_value_")
                    .map(|slot| format!("hidden_tip5_present_{slot}"))
            })
            .or_else(|| (label == "mmcs_bit").then(|| String::from("mmcs_bit_present")))
    }

    fn seed_terminal_npo_polynomial_fri_challenger(
        challenger: &mut TerminalFriChallenger,
        prelude: &TerminalProofPrelude,
        profile: &TerminalNpoPolynomialFriProfile,
    ) {
        Self::observe_terminal_fri_str(challenger, "nock-terminal-npo-polynomial-fri-v1");
        for limb in prelude.challenge_digest.0 {
            challenger.observe(Goldilocks::from_u64(limb));
        }
        for limb in prelude.public_values_digest.0 {
            challenger.observe(Goldilocks::from_u64(limb));
        }
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.security_bits as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.log_blowup as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.num_queries as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.parameters.query_pow_bits as u64);
        Self::observe_terminal_fri_u64(challenger, prelude.query_pow_nonce);
        Self::observe_terminal_fri_u64(challenger, profile.column_set as u64);
        Self::observe_terminal_fri_u64(challenger, profile.rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.padded_rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.log_rows as u64);
        Self::observe_terminal_fri_u64(challenger, profile.field_basis_dimension as u64);
        Self::observe_terminal_fri_u64(challenger, profile.field_columns as u64);
        Self::observe_terminal_fri_u64(challenger, profile.basis_columns as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.scheme_id as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.log_blowup as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.num_queries as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.query_pow_bits as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.max_log_arity as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.log_final_poly_len as u64);
        Self::observe_terminal_fri_u64(challenger, profile.proximity.pure_query_bits as u64);
    }

