    #[test]
    fn goldilocks_npo_exhaustive_residual_component_mapping_tracks_layout() {
        let (circuit, _public_inputs, _private_data) = build_many_merkle_tip5_test_circuit(1);
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let profile = NativeTerminalCompiler::terminal_npo_polynomial_profile::<Goldilocks>(&vk);
        assert_eq!(profile.sampled_residual_components, 10);
        assert_eq!(profile.residual_components, 17);

        for residual_index in 0..profile.residual_components {
            let component =
                NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<
                    Goldilocks,
                >(&vk, residual_index)
                .expect("residual component must map to an NPO row");
            assert_eq!(component.npo_index, 0);
            assert_eq!(component.component_offset, residual_index);
            assert_eq!(component.basis_component, 0);
        }
        assert!(
            NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<Goldilocks>(
                &vk,
                profile.residual_components,
            )
            .is_none()
        );

        let mmcs_component =
            NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<Goldilocks>(
                &vk, 10,
            )
            .expect("MMCS-bit residual component must exist");
        assert_eq!(mmcs_component.kind, TerminalNpoResidualKind::Tip5MmcsBit);
        assert_eq!(mmcs_component.limb, 16);

        let first_capacity_zero_component =
            NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<Goldilocks>(
                &vk, 11,
            )
            .expect("first capacity-zero residual component must exist");
        assert_eq!(
            first_capacity_zero_component.kind,
            TerminalNpoResidualKind::Tip5ChainInput
        );
        assert_eq!(first_capacity_zero_component.limb, 10);

        let last_capacity_zero_component =
            NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<Goldilocks>(
                &vk, 16,
            )
            .expect("last capacity-zero residual component must exist");
        assert_eq!(
            last_capacity_zero_component.kind,
            TerminalNpoResidualKind::Tip5ChainInput
        );
        assert_eq!(last_capacity_zero_component.limb, 15);
    }

    #[test]
    fn goldilocks_npo_exhaustive_residual_values_include_mmcs_booleanity() {
        let (circuit, public_inputs, private_data) = build_many_merkle_tip5_test_circuit(1);
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let witness =
            execute_tip5_terminal_witness_with_private_data(&circuit, public_inputs, private_data);
        let mmcs_bit = vk
            .npo_relation()
            .rows
            .iter()
            .find_map(|row| row.callsite.tip5_mmcs_bit)
            .expect("Merkle Tip5 row must bind an MMCS direction bit");
        let mut bad_witness_values = witness_values(&witness);
        bad_witness_values[mmcs_bit.0 as usize] = Goldilocks::from_u64(2);
        let mut bad_traces = witness.traces.clone();
        bad_traces.witness_trace = WitnessTrace::new(bad_witness_values);
        let bad_witness = TerminalWitness {
            fingerprint: witness.fingerprint,
            public_inputs: witness.public_inputs.clone(),
            private_inputs: witness.private_inputs.clone(),
            traces: bad_traces,
        };

        let sampled_values = compiler
            .terminal_npo_validity_values_goldilocks(&vk, &bad_witness)
            .expect("sampled NPO validity values must compute");
        assert!(
            sampled_values
                .iter()
                .all(|value| *value == Goldilocks::ZERO),
            "legacy sampled validity does not cover MMCS-bit booleanity"
        );

        let exhaustive_values = compiler
            .terminal_npo_exhaustive_residual_values_goldilocks(&vk, &bad_witness)
            .expect("exhaustive NPO residual values must compute");
        let mmcs_component =
            NativeTerminalCompiler::terminal_npo_exhaustive_residual_component_row::<Goldilocks>(
                &vk, 10,
            )
            .expect("MMCS-bit residual component must exist");
        assert_eq!(mmcs_component.kind, TerminalNpoResidualKind::Tip5MmcsBit);
        assert_eq!(exhaustive_values[10], Goldilocks::from_u64(2));
        let nonzero_values = exhaustive_values
            .iter()
            .filter(|value| **value != Goldilocks::ZERO)
            .copied()
            .collect::<Vec<_>>();
        assert_eq!(nonzero_values, vec![Goldilocks::from_u64(2)]);
    }

    #[test]
    fn goldilocks_npo_exhaustive_residual_fold_proof_verifies() {
        let (circuit, public_inputs, private_data) = build_many_merkle_tip5_test_circuit(2);
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let witness = execute_tip5_terminal_witness_with_private_data(
            &circuit,
            public_inputs.clone(),
            private_data,
        );
        let residual_oracle = compiler
            .commit_terminal_npo_exhaustive_residuals_goldilocks(&vk, &witness)
            .expect("exhaustive NPO residual oracle must commit");
        let residual_commitment = residual_oracle.commitment();
        let prelude = compiler
            .build_proof_prelude_goldilocks(
                &vk,
                &public_inputs,
                TerminalProofParameters::production_60bit(),
                vec![residual_commitment.root],
            )
            .expect("prelude must bind exhaustive NPO residual oracle");

        let proof = compiler
            .prove_terminal_npo_exhaustive_residual_fold_goldilocks(
                &vk,
                &public_inputs,
                &prelude,
                &residual_oracle,
                &witness,
            )
            .expect("exhaustive NPO residual fold proof must build");
        let plan = compiler
            .verify_terminal_npo_exhaustive_residual_fold_goldilocks::<Goldilocks>(
                &vk,
                &public_inputs,
                &prelude,
                &residual_commitment,
                &proof,
            )
            .expect("exhaustive NPO residual fold proof must verify");
        assert_eq!(
            plan.oracle_label,
            NativeTerminalCompiler::npo_exhaustive_residual_oracle_label()
        );
        assert_eq!(
            plan.indices.len(),
            TerminalProofParameters::production_60bit().num_queries as usize
        );
        for (round, commitment) in proof.fold_commitments.iter().enumerate() {
            assert_eq!(
                commitment.label,
                NativeTerminalCompiler::npo_exhaustive_residual_fold_oracle_label(round)
            );
        }
    }

