    #[test]
    fn goldilocks_d2_npo_polynomial_columns_cover_recompose_rows() {
        let (circuit, public_inputs) = build_recompose_test_circuit();
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let witness = execute_recompose_terminal_witness(&circuit, public_inputs);
        let table = compiler
            .terminal_npo_polynomial_table_goldilocks(&vk, &witness)
            .expect("D2 recompose NPO polynomial table must build");
        let columns = compiler
            .terminal_npo_polynomial_columns_goldilocks(&vk, &witness)
            .expect("D2 recompose NPO polynomial columns must build");
        let derived_residuals = compiler
            .terminal_npo_polynomial_column_residual_values_goldilocks(&vk, &columns)
            .expect("D2 recompose NPO polynomial column predicate must evaluate");
        assert_eq!(derived_residuals, table.residual_values);

        assert_eq!(columns.layout.rows, 2);
        assert_eq!(columns.layout.input_value_columns, 2);
        assert_eq!(columns.layout.input_present_columns, 2);
        assert_eq!(columns.layout.output_value_columns, 1);
        assert_eq!(columns.layout.output_present_columns, 1);
        assert_eq!(columns.layout.hidden_tip5_value_columns, 0);
        assert_eq!(columns.layout.hidden_tip5_present_columns, 0);
        assert_eq!(columns.layout.residual_value_columns, 6);
        assert_eq!(columns.layout.residual_present_columns, 6);
        assert_eq!(
            npo_polynomial_column(&columns, "is_tip5"),
            &[GoldilocksD2::ZERO, GoldilocksD2::ZERO]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "is_recompose"),
            &[GoldilocksD2::ONE, GoldilocksD2::ZERO]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "is_recompose_coeff"),
            &[GoldilocksD2::ZERO, GoldilocksD2::ONE]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "input_present_0"),
            &[GoldilocksD2::ONE, GoldilocksD2::ONE]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "input_present_1"),
            &[GoldilocksD2::ONE, GoldilocksD2::ONE]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "output_present_0"),
            &[GoldilocksD2::ONE, GoldilocksD2::ONE]
        );
        assert_eq!(
            npo_polynomial_column(&columns, "mmcs_bit_present"),
            &[GoldilocksD2::ZERO, GoldilocksD2::ZERO]
        );

        let mut reconstructed_residuals = Vec::new();
        for row in 0..columns.layout.rows {
            for slot in 0..columns.layout.residual_value_columns {
                if npo_polynomial_column(&columns, &format!("residual_present_{slot}"))[row]
                    == GoldilocksD2::ONE
                {
                    reconstructed_residuals.push(
                        npo_polynomial_column(&columns, &format!("residual_value_{slot}"))[row],
                    );
                }
            }
        }
        assert_eq!(reconstructed_residuals, table.residual_values);
        assert!(
            reconstructed_residuals
                .iter()
                .all(|value| *value == GoldilocksD2::ZERO)
        );

        let mut tampered_columns = columns.clone();
        let input_column = tampered_columns
            .labels
            .iter()
            .position(|label| label == "input_value_0")
            .expect("input column must exist");
        tampered_columns.columns[input_column][0] += GoldilocksD2::ONE;
        let err = compiler
            .terminal_npo_polynomial_column_residual_values_goldilocks(&vk, &tampered_columns)
            .expect_err("tampered recompose input column must change derived residuals");
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialResidualMismatch { npo_index: 0, .. }
        ));
    }

    #[test]
    fn goldilocks_d2_npo_polynomial_columns_commit_through_terminal_fri() {
        let (circuit, public_inputs) = build_recompose_test_circuit();
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let witness = execute_recompose_terminal_witness(&circuit, public_inputs.clone());
        let columns = compiler
            .terminal_npo_polynomial_columns_goldilocks(&vk, &witness)
            .expect("D2 recompose NPO polynomial columns must build");
        let verifier_columns = compiler
            .terminal_npo_polynomial_verifier_derived_columns_goldilocks::<GoldilocksD2>(&vk)
            .expect("D2 verifier-derived NPO polynomial columns must build");
        assert_eq!(verifier_columns.layout, columns.layout);
        assert_eq!(verifier_columns.labels, columns.labels);
        let mut verifier_derived = 0usize;
        let mut witness_value = 0usize;
        let mut residual_value = 0usize;
        for (column_index, label) in columns.labels.iter().enumerate() {
            if NativeTerminalCompiler::terminal_npo_polynomial_label_is_verifier_derived(label) {
                verifier_derived += 1;
                assert_eq!(
                    verifier_columns.columns[column_index], columns.columns[column_index],
                    "verifier-derived NPO column {label} must not depend on witness material",
                );
            } else if NativeTerminalCompiler::terminal_npo_polynomial_label_is_witness_value(label)
            {
                witness_value += 1;
            } else if NativeTerminalCompiler::terminal_npo_polynomial_label_is_residual_value(label)
            {
                residual_value += 1;
            } else {
                panic!("unclassified NPO polynomial column label {label}");
            }
        }
        assert_eq!(
            verifier_derived + witness_value + residual_value,
            columns.layout.column_count
        );
        assert_eq!(witness_value, 4);
        assert_eq!(residual_value, columns.layout.residual_value_columns);
        let (profile, matrix) =
            NativeTerminalCompiler::terminal_npo_polynomial_basis_matrix_goldilocks(&columns)
                .expect("D2 NPO columns must basis-expand into a terminal FRI matrix");
        assert_eq!(profile.rows, 2);
        assert_eq!(profile.padded_rows, 2);
        assert_eq!(profile.field_basis_dimension, 2);
        assert_eq!(profile.field_columns, columns.layout.column_count);
        assert_eq!(profile.basis_columns, columns.layout.column_count * 2);
        assert_eq!(
            profile.proximity,
            TerminalProximityProfile::production_60bit()
        );
        assert_eq!(matrix.height(), profile.padded_rows);
        assert_eq!(matrix.width(), profile.basis_columns);

        let column_roots =
            NativeTerminalCompiler::commit_terminal_npo_polynomial_column_values_goldilocks(
                &columns,
            )
            .expect("NPO column roots must commit")
            .commitments()
            .into_iter()
            .map(|commitment| commitment.root)
            .collect::<Vec<_>>();
        let prelude = compiler
            .build_proof_prelude_goldilocks(
                &vk,
                &public_inputs,
                TerminalProofParameters::production_60bit(),
                column_roots,
            )
            .expect("terminal NPO FRI prelude must build");
        let proof = compiler
            .prove_terminal_npo_polynomial_fri_opening_goldilocks(
                &vk,
                &public_inputs,
                &witness,
                &prelude,
            )
            .expect("typed terminal NPO FRI opening proof must build");
        assert_eq!(proof.profile, profile);
        assert_eq!(proof.opened_values_basis.len(), profile.basis_columns);
        compiler
            .verify_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &proof,
            )
            .expect("typed terminal NPO FRI opening proof must verify");
        let serialized = postcard::to_allocvec(&proof)
            .expect("typed terminal NPO FRI opening proof must serialize");
        let restored_fri = NativeTerminalCompiler::decompress_terminal_fri_proof(&proof.proof)
            .expect("typed terminal NPO FRI compact proof must decompress");
        let compact_fri_bytes = postcard::to_allocvec(&proof.proof)
            .expect("typed terminal NPO FRI compact proof must serialize");
        let plain_fri_bytes = postcard::to_allocvec(&restored_fri)
            .expect("typed terminal NPO FRI proof must serialize");
        assert!(
            compact_fri_bytes.len() < plain_fri_bytes.len(),
            "terminal NPO polynomial FRI proof should store compact path material"
        );
        let (roundtrip, trailing): (TerminalNpoPolynomialFriOpeningProof, &[u8]) =
            postcard::take_from_bytes(&serialized)
                .expect("typed terminal NPO FRI opening proof must deserialize");
        assert!(trailing.is_empty());
        compiler
            .verify_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &roundtrip,
            )
            .expect("round-tripped terminal NPO FRI opening proof must verify");
        let opened_full = compiler
            .verify_and_open_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &roundtrip,
            )
            .expect("typed terminal NPO FRI opened columns must verify");
        assert_eq!(opened_full.profile, profile);
        assert_eq!(opened_full.labels, columns.labels);
        assert_eq!(opened_full.values.len(), profile.field_columns);
        assert!(
            opened_full
                .values
                .iter()
                .all(|basis| basis.len() == profile.field_basis_dimension)
        );

        let (value_profile, value_matrix) =
            NativeTerminalCompiler::terminal_npo_polynomial_value_basis_matrix_goldilocks(&columns)
                .expect("D2 NPO value columns must basis-expand into a terminal FRI matrix");
        assert_eq!(
            value_profile.column_set,
            TerminalNpoPolynomialFriColumnSet::WitnessValues
        );
        assert!(value_profile.field_columns < profile.field_columns);
        assert_eq!(value_matrix.height(), value_profile.padded_rows);
        assert_eq!(value_matrix.width(), value_profile.basis_columns);
        let value_proof = compiler
            .prove_terminal_npo_polynomial_value_fri_opening_goldilocks(
                &vk,
                &public_inputs,
                &witness,
                &prelude,
            )
            .expect("typed terminal NPO value-column FRI opening proof must build");
        assert_eq!(value_proof.profile, value_profile);
        compiler
            .verify_terminal_npo_polynomial_value_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &value_proof,
            )
            .expect("typed terminal NPO value-column FRI opening proof must verify");
        let restored_value_fri =
            NativeTerminalCompiler::decompress_terminal_fri_proof(&value_proof.proof)
                .expect("typed terminal NPO value-column compact proof must decompress");
        let compact_value_fri_bytes = postcard::to_allocvec(&value_proof.proof)
            .expect("typed terminal NPO value-column compact proof must serialize");
        let plain_value_fri_bytes = postcard::to_allocvec(&restored_value_fri)
            .expect("typed terminal NPO value-column FRI proof must serialize");
        assert!(
            compact_value_fri_bytes.len() < plain_value_fri_bytes.len(),
            "terminal NPO value-column FRI proof should store compact path material"
        );
        let opened_value = compiler
            .verify_and_open_terminal_npo_polynomial_value_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &value_proof,
            )
            .expect("typed terminal NPO value-column FRI opened columns must verify");
        assert_eq!(opened_value.profile, value_profile);
        assert_eq!(
            opened_value.labels,
            vec![
                String::from("input_value_0"),
                String::from("input_value_1"),
                String::from("output_value_0"),
                String::from("mmcs_bit"),
            ]
        );
        assert!(opened_value.labels.iter().all(|label| {
            NativeTerminalCompiler::terminal_npo_polynomial_label_is_witness_value(label)
        }));
        assert_eq!(opened_value.values.len(), value_profile.field_columns);
        assert!(
            opened_value
                .values
                .iter()
                .all(|basis| basis.len() == value_profile.field_basis_dimension)
        );
        assert_ne!(
            opened_full.zeta, opened_value.zeta,
            "terminal NPO FRI opening point must be column-set/profile bound",
        );
        compiler
            .verify_terminal_npo_polynomial_value_padding_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &value_proof,
            )
            .expect("honest value-column FRI openings must satisfy verifier-derived padding");
        let padding_quotient_proof = compiler
            .prove_terminal_npo_polynomial_padding_quotient_goldilocks(
                &vk,
                &public_inputs,
                &witness,
                &prelude,
            )
            .expect("honest terminal NPO padding quotient proof must build");
        assert_eq!(padding_quotient_proof.value_profile, value_profile);
        assert_eq!(
            padding_quotient_proof.quotient_profile.column_set,
            TerminalNpoPolynomialFriColumnSet::PaddingQuotient
        );
        assert_eq!(
            padding_quotient_proof.opened_quotient_basis.len(),
            padding_quotient_proof.quotient_profile.basis_columns
        );
        let opened_padding = compiler
            .verify_terminal_npo_polynomial_padding_quotient_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &padding_quotient_proof,
            )
            .expect("honest terminal NPO padding quotient proof must verify");
        assert_eq!(opened_padding.labels, opened_value.labels);
        let serialized = postcard::to_allocvec(&padding_quotient_proof)
            .expect("padding quotient proof must serialize");
        let restored_fri =
            NativeTerminalCompiler::decompress_terminal_fri_proof(&padding_quotient_proof.proof)
                .expect("compressed terminal padding quotient FRI proof must decompress");
        let compressed_fri_bytes = postcard::to_allocvec(&padding_quotient_proof.proof)
            .expect("compressed terminal padding quotient FRI proof must serialize");
        let plain_fri_bytes =
            postcard::to_allocvec(&restored_fri).expect("plain terminal FRI proof must serialize");
        println!(
            "terminal NPO padding quotient candidate: {} bytes ({:.1} KiB), stored compact FRI plain={} bytes ({:.1} KiB) compressed={} bytes ({:.1} KiB)",
            serialized.len(),
            serialized.len() as f64 / 1024.0,
            plain_fri_bytes.len(),
            plain_fri_bytes.len() as f64 / 1024.0,
            compressed_fri_bytes.len(),
            compressed_fri_bytes.len() as f64 / 1024.0,
        );
        assert!(
            compressed_fri_bytes.len() < plain_fri_bytes.len(),
            "terminal compressed FRI should reduce padding quotient path material"
        );
        let (roundtrip_padding, trailing): (TerminalNpoPolynomialPaddingQuotientProof, &[u8]) =
            postcard::take_from_bytes(&serialized)
                .expect("padding quotient proof must deserialize");
        assert!(trailing.is_empty());
        compiler
            .verify_terminal_npo_polynomial_padding_quotient_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &roundtrip_padding,
            )
            .expect("round-tripped padding quotient proof must verify");

        let mut bad_padding_columns = columns.clone();
        let mmcs_column = bad_padding_columns
            .labels
            .iter()
            .position(|label| label == "mmcs_bit")
            .expect("MMCS value column must exist");
        bad_padding_columns.columns[mmcs_column][0] = GoldilocksD2::ONE;
        let bad_padding_proof =
            NativeTerminalCompiler::prove_terminal_npo_polynomial_fri_opening_from_columns_goldilocks(
                &prelude,
                &bad_padding_columns,
                TerminalNpoPolynomialFriColumnSet::WitnessValues,
            )
            .expect("FRI-valid but padding-invalid value-column proof must build");
        compiler
            .verify_and_open_terminal_npo_polynomial_value_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &bad_padding_proof,
            )
            .expect("padding-invalid value-column proof is still a valid FRI opening");
        let err = compiler
            .verify_terminal_npo_polynomial_value_padding_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &bad_padding_proof,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch { label }
                if label == "mmcs_bit"
        ));
        let bad_padding_quotient_proof =
            NativeTerminalCompiler::prove_terminal_npo_polynomial_padding_quotient_from_columns_goldilocks(
                &prelude,
                &bad_padding_columns,
                &verifier_columns,
            )
            .expect("FRI-valid but quotient-invalid padding proof must build");
        let err = compiler
            .verify_terminal_npo_polynomial_padding_quotient_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &bad_padding_quotient_proof,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch { label }
                if label == "npo_value_relation_quotient"
        ));

        let mut bad_present_value_columns = columns.clone();
        let input_column = bad_present_value_columns
            .labels
            .iter()
            .position(|label| label == "input_value_0")
            .expect("input value column must exist");
        bad_present_value_columns.columns[input_column][0] += GoldilocksD2::ONE;
        let bad_present_value_proof =
            NativeTerminalCompiler::prove_terminal_npo_polynomial_fri_opening_from_columns_goldilocks(
                &prelude,
                &bad_present_value_columns,
                TerminalNpoPolynomialFriColumnSet::WitnessValues,
            )
            .expect("FRI-valid proof with malformed present input value must build");
        compiler
            .verify_terminal_npo_polynomial_value_padding_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &bad_present_value_proof,
            )
            .expect("padding-only checker must not claim full present-value row semantics");
        let bad_recompose_quotient_proof =
            NativeTerminalCompiler::prove_terminal_npo_polynomial_padding_quotient_from_columns_goldilocks(
                &prelude,
                &bad_present_value_columns,
                &verifier_columns,
            )
            .expect("FRI-valid but recompose-invalid value quotient proof must build");
        let err = compiler
            .verify_terminal_npo_polynomial_padding_quotient_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &bad_recompose_quotient_proof,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch { label }
                if label == "npo_value_relation_quotient"
        ));
        let err = compiler
            .verify_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &value_proof,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch { .. }
        ));

        let (pcs, _) = NativeTerminalCompiler::terminal_fri_pcs_and_challenger(profile.proximity)
            .expect("terminal FRI PCS must build");
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                profile.padded_rows,
            );
        let zeta = TerminalFriChallenge::from_basis_coefficients_fn(|basis| {
            if basis == 0 {
                Goldilocks::from_u64(19)
            } else {
                Goldilocks::ONE
            }
        });
        for label in ["is_recompose", "input_present_0", "residual_present_0"] {
            let column_index = columns
                .labels
                .iter()
                .position(|candidate| candidate == label)
                .expect("deterministic column label must exist");
            assert!(
                NativeTerminalCompiler::terminal_npo_polynomial_label_is_verifier_derived(label)
            );
            let basis_column = column_index * profile.field_basis_dimension;
            let mut from_full_matrix = Vec::with_capacity(profile.padded_rows);
            let mut from_verifier_columns = Vec::with_capacity(profile.padded_rows);
            for row in 0..profile.padded_rows {
                from_full_matrix.push(matrix.values[row * profile.basis_columns + basis_column]);
                let value = if row < verifier_columns.layout.rows {
                    verifier_columns.columns[column_index][row]
                        .as_basis_coefficients_slice()
                        .first()
                        .copied()
                        .unwrap_or(Goldilocks::ZERO)
                } else {
                    Goldilocks::ZERO
                };
                from_verifier_columns.push(value);
            }
            assert_eq!(from_full_matrix, from_verifier_columns);
            assert_eq!(
                domain.evaluate_polynomial_at(&from_full_matrix, zeta),
                domain.evaluate_polynomial_at(&from_verifier_columns, zeta),
                "verifier-derived basis column {label} must interpolate to the committed full-table value",
            );
        }

        let mut tampered_opening = proof.clone();
        tampered_opening.opened_values_basis[0][0] =
            tampered_opening.opened_values_basis[0][0].wrapping_add(1);
        let err = compiler
            .verify_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &tampered_opening,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification { .. }
        ));

        let mut tampered_profile = proof;
        tampered_profile.profile.basis_columns += 1;
        let err = compiler
            .verify_terminal_npo_polynomial_fri_opening_goldilocks::<GoldilocksD2>(
                &vk,
                &public_inputs,
                &prelude,
                &tampered_profile,
            )
            .unwrap_err();
        assert!(matches!(
            err,
            NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch { .. }
        ));
    }

    #[test]
    fn goldilocks_terminal_npo_row_evaluations_report_tip5_residuals() {
        let (circuit, public_inputs) = build_tip5_test_circuit();
        let compiler = NativeTerminalCompiler::new("nock-terminal-v0", 60);
        let (_pk, vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let witness = execute_tip5_terminal_witness(&circuit, public_inputs);
        let witness_values = witness_values(&witness);
        let relation = vk.npo_relation();
        let row = relation
            .rows
            .iter()
            .find(|row| row.kind == TerminalNpoRowKind::Tip5Goldilocks)
            .expect("Tip5 NPO row must be projected");
        let expected_witness_ids = NativeTerminalCompiler::npo_callsite_witness_ids(&row.callsite);
        let opened_values = expected_witness_ids
            .iter()
            .map(|witness_id| witness_values[witness_id.0 as usize])
            .collect::<Vec<_>>();

        let evaluation = compiler
            .evaluate_sampled_tip5_npo_row_values::<Goldilocks>(
                row.npo_index,
                row.local_row,
                &row.callsite,
                &[],
                &expected_witness_ids,
                &opened_values,
            )
            .expect("honest Tip5 row must evaluate");
        assert!(evaluation.is_satisfied());

        let output_witness_id = row
            .callsite
            .outputs
            .iter()
            .copied()
            .flatten()
            .next()
            .expect("Tip5 row must bind an output witness");
        let output_pos = expected_witness_ids
            .iter()
            .position(|witness_id| *witness_id == output_witness_id)
            .expect("output witness must be opened");
        let mut bad_opened_values = opened_values;
        bad_opened_values[output_pos] += Goldilocks::ONE;
        let evaluation = compiler
            .evaluate_sampled_tip5_npo_row_values::<Goldilocks>(
                row.npo_index,
                row.local_row,
                &row.callsite,
                &[],
                &expected_witness_ids,
                &bad_opened_values,
            )
            .expect("tampered Tip5 row still has a well-formed evaluation");
        let residual = evaluation
            .first_nonzero()
            .expect("tampered Tip5 output must produce a residual");
        assert_eq!(residual.kind, TerminalNpoResidualKind::Tip5Output);
        assert!(!residual.is_zero());
    }

